import React, { useState } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this setlist?')) {
        await storage.deleteSetlist(id);
        onRefresh();
    }
  };

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>
                <div className="space-y-2">
                    {sheets.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <span className="text-slate-200 truncate">{sheet.name}</span>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex justify-between items-center mb-8">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <button 
          onClick={startCreate}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all"
        >
          <Plus size={20} />
          <span>New Setlist</span>
        </button>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one to organize your performance</p>
        </div>
      ) : (
        <div className="space-y-4">
          {setlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDelete(e, list.id)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2 } from 'lucide-react';
import { Stroke, Point } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs for drawing
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Load Content
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      try {
        // Load Blob
        const blob = await storage.getSheetBlob(sheetId);
        if (blob && active) {
          const url = URL.createObjectURL(blob);
          setBlobUrl(url);
          setFileType(blob.type);
        }

        // Load Annotations
        const storedAnnotations = await storage.getAnnotation(sheetId);
        if (storedAnnotations && active) {
          setStrokes(storedAnnotations.strokes);
        } else {
          setStrokes([]);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();

    return () => {
      active = false;
      if (blobUrl) URL.revokeObjectURL(blobUrl);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sheetId]);

  // Sync dimensions for SVG ViewBox
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        // Only update if changed to avoid loops (though strict equality check in React state helps)
        setDimensions(prev => 
          (prev.width !== clientWidth || prev.height !== clientHeight) 
            ? { width: clientWidth, height: clientHeight } 
            : prev
        );
      }
    };

    // Initial check
    updateDimensions();

    // Listen for resizes
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) {
      resizeObserver.observe(containerRef.current);
    }

    return () => resizeObserver.disconnect();
  }, [loading, fileType]);

  // Save Annotations on change
  useEffect(() => {
    if (!loading) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheetId, strokes);
      }, 500); // Debounce save
      return () => clearTimeout(timeout);
    }
  }, [strokes, sheetId, loading]);

  // Bluetooth Pedal / Keyboard Listeners
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        if (hasNext) onNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        if (hasPrev) onPrev();
      } else if (e.key === 'Escape') {
        onClose();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onNext, onPrev, hasNext, hasPrev, onClose]);

  // --- Drawing Logic ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    if (!svgRef.current) return null;
    const svg = svgRef.current;
    const CTM = svg.getScreenCTM();
    if (!CTM) return null;

    let clientX, clientY;
    if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - CTM.e) / CTM.a,
      y: (clientY - CTM.f) / CTM.d,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 100; // Squared distance threshold
    setStrokes(prev => prev.filter(stroke => {
      // Check if any segment in the stroke is close to the eraser point
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false; // Remove this stroke
        }
      }
      return true; // Keep stroke
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode || fileType === 'application/pdf') return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode || fileType === 'application/pdf') return;

    // If not drawing and not erasing (mouse hover), do nothing
    // For touch, touchmove implies interaction
    if (!currentStroke && tool !== 'eraser') return;
    if (tool === 'eraser' && !('touches' in e) && !(e.buttons === 1)) return; // Mouse eraser needs click

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    setStrokes(prev => prev.slice(0, -1));
  };

  const handleClear = () => {
    if (strokes.length > 0 && confirm('Are you sure you want to clear all annotations? This cannot be undone.')) {
      setStrokes([]);
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return d;
  };

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar (Overlay) */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
           {fileType !== 'application/pdf' ? (
               <>
                 <button 
                    onClick={() => setIsDrawingMode(!isDrawingMode)} 
                    className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                    title={isDrawingMode ? "Done Drawing" : "Annotate"}
                 >
                    <PenTool size={18} />
                 </button>

                 {isDrawingMode && (
                   <>
                      <div className="h-6 w-px bg-white/20 mx-1" />

                      {/* Tool Switcher */}
                      <button 
                        onClick={() => setTool('pen')}
                        className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                      >
                         <PenTool size={18} />
                      </button>
                      <button 
                        onClick={() => setTool('eraser')}
                        className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                      >
                         <Eraser size={18} />
                      </button>

                      {tool === 'pen' && (
                        <div className="flex items-center gap-1 ml-2">
                            {COLORS.map(c => (
                                <button 
                                  key={c}
                                  onClick={() => setColor(c)}
                                  className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                                  style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>
                      )}

                      <div className="h-6 w-px bg-white/20 mx-1" />

                      <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                        <Undo size={18} />
                      </button>

                      <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear All">
                        <Trash2 size={18} />
                      </button>
                   </>
                 )}
               </>
           ) : (
             <span className="text-xs text-amber-400 px-2">PDF: Read Only</span>
           )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {loading ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            fileType === 'application/pdf' ? (
                // PDF Viewer
                <iframe src={`${blobUrl}#toolbar=0&navpanes=0`} className="w-full h-full" title="Sheet Music PDF" />
            ) : (
                // Image Viewer + Annotation Canvas
                <div 
                    ref={containerRef}
                    className="relative w-full h-full flex items-center justify-center touch-none select-none"
                    onMouseDown={handlePointerDown}
                    onMouseMove={handlePointerMove}
                    onMouseUp={handlePointerUp}
                    onMouseLeave={handlePointerUp}
                    onTouchStart={handlePointerDown}
                    onTouchMove={handlePointerMove}
                    onTouchEnd={handlePointerUp}
                >
                    {/* The Image */}
                    <img 
                        src={blobUrl} 
                        alt="Music Sheet" 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />

                    {/* SVG Overlay for Annotations */}
                    <svg 
                        ref={svgRef}
                        className="absolute inset-0 w-full h-full pointer-events-none" 
                        viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                        preserveAspectRatio="none"
                    >
                        {strokes.map((stroke, i) => (
                            <path 
                                key={i}
                                d={getSvgPath(stroke.points)}
                                stroke={stroke.color}
                                strokeWidth={stroke.width}
                                fill="none"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                        ))}
                        {currentStroke && (
                            <path 
                                d={getSvgPath(currentStroke.points)}
                                stroke={currentStroke.color}
                                strokeWidth={currentStroke.width}
                                fill="none"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                        )}
                        {/* Cursor for Eraser (Desktop only visual aid) */}
                        {isDrawingMode && tool === 'eraser' && !('ontouchstart' in window) && (
                           <circle r="10" fill="rgba(255,255,255,0.2)" stroke="white" className="pointer-events-none hidden group-hover:block" />
                        )}
                    </svg>
                </div>
            )
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones (Invisible but clickable) - DISABLED WHEN DRAWING */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[15%] z-10 cursor-pointer" onClick={onPrev} />
            <div className="absolute inset-y-0 right-0 w-[15%] z-10 cursor-pointer" onClick={onNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint - Fade out if drawing */}
      {!isDrawingMode && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${!hasPrev ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={onPrev}
             disabled={!hasPrev}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${!hasNext ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={onNext}
             disabled={!hasNext}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

export interface Point {
  x: number;
  y: number;
}

export interface Stroke {
  points: Point[];
  color: string;
  width: number;
}

export interface Sheet {
  id: string;
  name: string;
  tags: string[]; // Added for filtering/organization
  fileType: 'image/png' | 'image/jpeg' | 'application/pdf';
  dateAdded: number;
  blob?: Blob; // Not stored in main state, fetched on demand
  previewUrl?: string; // For images
}

export interface AnnotationLayer {
  sheetId: string;
  strokes: Stroke[];
}

export interface Setlist {
  id: string;
  name: string;
  sheetIds: string[]; // Ordered list of sheet IDs
  dateCreated: number;
}

export enum AppView {
  LIBRARY = 'LIBRARY',
  SETLISTS = 'SETLISTS',
  VIEWER = 'VIEWER',
}

export interface ViewerState {
  activeSetlistId: string | null; // null if viewing single file from library
  queue: string[]; // Sheet IDs in order
  currentIndex: number;
}

import { DB_NAME, DB_VERSION, STORES } from '../constants';
import { Sheet, Setlist, AnnotationLayer } from '../types';

// Simple Promise-based wrapper for IndexedDB
class StorageService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => reject(request.error);
      request.onsuccess = () => {
        this.db = request.result;
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        if (!db.objectStoreNames.contains(STORES.SHEETS)) {
          db.createObjectStore(STORES.SHEETS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.SETLISTS)) {
          db.createObjectStore(STORES.SETLISTS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.ANNOTATIONS)) {
          db.createObjectStore(STORES.ANNOTATIONS, { keyPath: 'sheetId' });
        }
      };
    });
  }

  // Generic helper
  private async transaction<T>(storeName: string, mode: IDBTransactionMode, callback: (store: IDBObjectStore) => IDBRequest | void): Promise<T> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const tx = this.db!.transaction(storeName, mode);
      const store = tx.objectStore(storeName);
      let request: IDBRequest | void;

      try {
        request = callback(store);
      } catch (e) {
        reject(e);
        return;
      }

      tx.oncomplete = () => resolve(request ? request.result : undefined);
      tx.onerror = () => reject(tx.error);
    });
  }

  // --- Sheets ---

  async addSheet(sheet: Sheet, blob: Blob): Promise<void> {
    // We store the blob directly in IDB
    const record = { ...sheet, blob };
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(record));
  }

  // Updates metadata (name, tags) without needing the blob again
  async updateSheetMetadata(sheet: Sheet): Promise<void> {
    const existing = await this.transaction<any>(STORES.SHEETS, 'readonly', (store) => store.get(sheet.id));
    if (!existing) throw new Error('Sheet not found');

    // Merge new metadata with existing blob
    const record = { ...existing, ...sheet };
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(record));
  }

  async getAllSheets(): Promise<Sheet[]> {
    return this.transaction(STORES.SHEETS, 'readonly', (store) => store.getAll());
  }

  async getSheetBlob(id: string): Promise<Blob | undefined> {
    const result = await this.transaction<{ blob: Blob }>(STORES.SHEETS, 'readonly', (store) => store.get(id));
    return result?.blob;
  }

  async deleteSheet(id: string): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.delete(id));
    // Cascade delete annotations
    await this.deleteAnnotation(id);
  }

  // --- Setlists ---

  async saveSetlist(setlist: Setlist): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.put(setlist));
  }

  async getAllSetlists(): Promise<Setlist[]> {
    return this.transaction(STORES.SETLISTS, 'readonly', (store) => store.getAll());
  }

  async deleteSetlist(id: string): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.delete(id));
  }

  // --- Annotations ---

  async saveAnnotation(sheetId: string, strokes: any[]): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.put({ sheetId, strokes }));
  }

  async getAnnotation(sheetId: string): Promise<AnnotationLayer | undefined> {
    return this.transaction(STORES.ANNOTATIONS, 'readonly', (store) => store.get(sheetId));
  }

  async deleteAnnotation(sheetId: string): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.delete(sheetId));
  }
}

export const storage = new StorageService();

import React, { useRef, useState, useMemo } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save } from 'lucide-react';
import { Sheet } from '../types';
import { storage } from '../services/storage';

interface LibraryProps {
  sheets: Sheet[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

const Library: React.FC<LibraryProps> = ({ sheets, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [tagInput, setTagInput] = useState('');

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          fileType: file.type as any,
          dateAdded: Date.now(),
        };
        await storage.addSheet(newSheet, file);
      }
      onRefresh();
    }
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Are you sure you want to delete this sheet?')) {
      await storage.deleteSheet(id);
      onRefresh();
    }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setTagInput('');
  };

  const handleAddTag = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && tagInput.trim()) {
      e.preventDefault();
      if (!editTags.includes(tagInput.trim())) {
        setEditTags([...editTags, tagInput.trim()]);
      }
      setTagInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags
      };
      await storage.updateSheetMetadata(updatedSheet);
      setEditingSheet(null);
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex gap-3">
            <div className="relative flex-1 md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search sheets or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>
            <button 
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95"
            >
                <Upload size={20} />
                <span className="hidden sm:inline">Import</span>
            </button>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => (
            <div 
              key={sheet.id}
              onClick={() => onSelect(sheet.id)}
              className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
            >
              <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                 <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                 {sheet.fileType === 'application/pdf' ? (
                     <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                 ) : (
                    <div className="flex flex-col items-center gap-2">
                         <Music size={48} className="text-slate-600" />
                         <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">Image</span>
                    </div>
                 )}
                 {/* Tag Badges */}
                 <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                    {(sheet.tags || []).slice(0, 3).map(tag => (
                        <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 px-1.5 py-0.5 rounded border border-blue-500/30 truncate max-w-full">
                            {tag}
                        </span>
                    ))}
                    {(sheet.tags || []).length > 3 && (
                        <span className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded">
                            +{sheet.tags!.length - 3}
                        </span>
                    )}
                 </div>
              </div>

              <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
              </div>

              {/* Action Buttons */}
              <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                  <button 
                    onClick={(e) => openEditModal(e, sheet)}
                    className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                    title="Edit Details"
                  >
                    <PenLine size={14} />
                  </button>
                  <button 
                    onClick={(e) => handleDelete(e, sheet.id)}
                    className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                    title="Delete"
                  >
                    <Trash2 size={14} />
                  </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setEditingSheet(null)}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={() => setEditingSheet(null)} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Tags (Genre, etc.)</label>
                          <div className="flex flex-wrap gap-2 mb-2 min-h-[32px]">
                              {editTags.map(tag => (
                                  <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                      {tag}
                                      <button onClick={() => handleRemoveTag(tag)} className="hover:text-white"><X size={12}/></button>
                                  </span>
                              ))}
                          </div>
                          <div className="relative">
                            <Tag size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                            <input 
                                type="text" 
                                placeholder="Type tag and hit Enter..."
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-9 pr-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                                onKeyDown={handleAddTag}
                            />
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={() => setEditingSheet(null)} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this setlist?')) {
        await storage.deleteSetlist(id);
        onRefresh();
    }
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>
            <button 
            onClick={startCreate}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
            >
            <Plus size={20} />
            <span className="hidden sm:inline">New Setlist</span>
            </button>
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one to organize your performance</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDelete(e, list.id)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Setlists;

export interface Point {
  x: number;
  y: number;
}

export interface Stroke {
  points: Point[];
  color: string;
  width: number;
  pageIndex: number; // Added to track which page the annotation belongs to
}

export interface SheetPage {
  blob: Blob;
  fileType: 'image/png' | 'image/jpeg' | 'application/pdf';
}

export interface Sheet {
  id: string;
  name: string;
  tags: string[]; 
  dateAdded: number;
  pages: SheetPage[]; // Replaced single blob with array of pages
  previewUrl?: string; // For images
}

export interface AnnotationLayer {
  sheetId: string;
  strokes: Stroke[];
}

export interface Setlist {
  id: string;
  name: string;
  sheetIds: string[]; // Ordered list of sheet IDs
  dateCreated: number;
}

export enum AppView {
  LIBRARY = 'LIBRARY',
  SETLISTS = 'SETLISTS',
  VIEWER = 'VIEWER',
}

