                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const preset = TAG_PRESETS.find(p => p.label === tag);
                            const Icon = preset ? preset.icon : Tag;
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDelete(e, sheet.id)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setEditingSheet(null)}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={() => setEditingSheet(null)} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const preset = TAG_PRESETS.find(p => p.label === tag);
                                  const Icon = preset ? preset.icon : Tag;
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {TAG_PRESETS.map(preset => {
                                  const isSelected = editTags.includes(preset.label);
                                  return (
                                    <button
                                        key={preset.label}
                                        onClick={() => isSelected ? handleRemoveTag(preset.label) : addTag(preset.label)}
                                        className={`flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                    >
                                        <preset.icon size={20} className="mb-1" />
                                        <span className="text-[10px]">{preset.label}</span>
                                    </button>
                                  )
                              })}
                          </div>

                          <div className="relative">
                            <Tag size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                            <input 
                                type="text" 
                                placeholder="Custom tag..."
                                className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-9 pr-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                                onKeyDown={handleAddTag}
                            />
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={() => setEditingSheet(null)} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2 } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Configure PDF.js worker
pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);

        if (loadedSheet && active) {
            setSheet(loadedSheet);
            // Load Annotations
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);

            // Initial Page Count Check (Image Array)
            // If it's a PDF, we update this after PDF loads
            if (loadedSheet.pages.length > 0) {
                 setNumPages(loadedSheet.pages.length);
            }
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL for Current "File" (which might be a multi-page PDF)
  // Note: For image arrays, this changes on pageIndex. For PDF, it stays constant.
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;

    // Logic: If the sheet contains multiple image files, pageIndex corresponds to sheet.pages[pageIndex].
    // If the sheet is a single PDF file (sheet.pages[0]), pageIndex corresponds to internal PDF page.
    // Simplification: We look at the first file. If it's PDF, we treat the whole sheet as that PDF.
    const isPdf = sheet.pages[0].fileType === 'application/pdf';

    let activeBlob: Blob;

    if (isPdf) {
        // Always use the first file (the PDF)
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        // Use the file corresponding to current index
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }

    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);

    return () => {
        URL.revokeObjectURL(url);
    };
  }, [sheet, pageIndex]);

  // 3. Load PDF Document (if applicable)
  useEffect(() => {
    if (fileType !== 'application/pdf' || !blobUrl) return;

    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjsLib.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                // Ensure pageIndex is valid for new doc
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [blobUrl, fileType]); // pageIndex removed to avoid reloading doc on turn

  // 4. Render PDF Page to Canvas
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;

    let renderTask: any = null;

    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);

            // Calculate scale to fit container
            const container = containerRef.current;
            if (!container) return;

            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });

            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98; // 2% margin

            const viewport = page.getViewport({ scale });

            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;

                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };

                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };

    renderPage();

    return () => {
        if (renderTask) renderTask.cancel();
    };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions for SVG ViewBox (Overlay)
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // --- Navigation ---

  const handlePageNext = () => {
    if (pageIndex < numPages - 1) {
        setPageIndex(prev => prev + 1);
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePagePrev = () => {
    if (pageIndex > 0) {
        setPageIndex(prev => prev - 1);
    } else if (hasPrev) {
        onPrev();
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);


  // --- Drawing Logic ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    if (!svgRef.current) return null;
    const svg = svgRef.current;
    const CTM = svg.getScreenCTM();
    if (!CTM) return null;

    let clientX, clientY;
    if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - CTM.e) / CTM.a,
      y: (clientY - CTM.f) / CTM.d,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 100; // Squared distance threshold
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    if (!currentStroke && tool !== 'eraser') return;
    if (tool === 'eraser' && !('touches' in e) && !(e.buttons === 1)) return; 

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return d;
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <span className="text-xs text-slate-300">Page {pageIndex + 1} / {numPages}</span>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <div className="flex items-center gap-1 ml-2">
                        {COLORS.map(c => (
                            <button 
                              key={c}
                              onClick={() => setColor(c)}
                              className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                            />
                        ))}
                    </div>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {loading ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className="relative w-full h-full flex items-center justify-center touch-none select-none"
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

const CACHE_NAME = 'opusview-v1';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json',
  'https://cdn.tailwindcss.com',
  'https://esm.sh/react@^19.2.1/',
  'https://esm.sh/react@^19.2.1',
  'https://esm.sh/lucide-react@^0.559.0',
  'https://esm.sh/react-dom@^19.2.1/',
  'https://esm.sh/pdfjs-dist@3.11.174',
  'https://esm.sh/pdfjs-dist@3.11.174/',
  'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js'
];

// Install event: cache core assets
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
  self.skipWaiting();
});

// Activate event: clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

// Fetch event: Network first, fall back to cache for HTML/API, Cache first for static assets
self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // For external CDNs (modules, tailwind), use Stale-While-Revalidate
  // This ensures fast load but updates eventually
  if (url.hostname === 'cdn.tailwindcss.com' || url.hostname === 'esm.sh' || url.hostname === 'cdn-icons-png.flaticon.com') {
    event.respondWith(
      caches.open(CACHE_NAME).then((cache) => {
        return cache.match(event.request).then((cachedResponse) => {
          const fetchPromise = fetch(event.request).then((networkResponse) => {
            cache.put(event.request, networkResponse.clone());
            return networkResponse;
          });
          return cachedResponse || fetchPromise;
        });
      })
    );
    return;
  }

  // For local files, try network first, then cache (to ensure development updates are seen)
  // In a production build, you might want Cache First for hashed assets.
  event.respondWith(
    fetch(event.request)
      .then((response) => {
        // Check if we received a valid response
        if (!response || response.status !== 200 || response.type !== 'basic') {
          return response;
        }
        const responseToCache = response.clone();
        caches.open(CACHE_NAME).then((cache) => {
          cache.put(event.request, responseToCache);
        });
        return response;
      })
      .catch(() => {
        return caches.match(event.request);
      })
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2 } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);

        if (loadedSheet && active) {
            setSheet(loadedSheet);
            // Load Annotations
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);

            // Initial Page Count Check (Image Array)
            // If it's a PDF, we update this after PDF loads
            if (loadedSheet.pages.length > 0) {
                 setNumPages(loadedSheet.pages.length);
            }
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL for Current "File" (which might be a multi-page PDF)
  // Note: For image arrays, this changes on pageIndex. For PDF, it stays constant.
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;

    // Logic: If the sheet contains multiple image files, pageIndex corresponds to sheet.pages[pageIndex].
    // If the sheet is a single PDF file (sheet.pages[0]), pageIndex corresponds to internal PDF page.
    // Simplification: We look at the first file. If it's PDF, we treat the whole sheet as that PDF.
    const isPdf = sheet.pages[0].fileType === 'application/pdf';

    let activeBlob: Blob;

    if (isPdf) {
        // Always use the first file (the PDF)
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        // Use the file corresponding to current index
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }

    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);

    return () => {
        URL.revokeObjectURL(url);
    };
  }, [sheet, pageIndex]);

  // 3. Load PDF Document (if applicable)
  useEffect(() => {
    if (fileType !== 'application/pdf' || !blobUrl) return;

    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                // Ensure pageIndex is valid for new doc
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [blobUrl, fileType]); // pageIndex removed to avoid reloading doc on turn

  // 4. Render PDF Page to Canvas
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;

    let renderTask: any = null;

    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);

            // Calculate scale to fit container
            const container = containerRef.current;
            if (!container) return;

            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });

            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98; // 2% margin

            const viewport = page.getViewport({ scale });

            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;

                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };

                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };

    renderPage();

    return () => {
        if (renderTask) renderTask.cancel();
    };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions for SVG ViewBox (Overlay)
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // --- Navigation ---

  const handlePageNext = () => {
    if (pageIndex < numPages - 1) {
        setPageIndex(prev => prev + 1);
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePagePrev = () => {
    if (pageIndex > 0) {
        setPageIndex(prev => prev - 1);
    } else if (hasPrev) {
        onPrev();
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);


  // --- Drawing Logic ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    if (!svgRef.current) return null;
    const svg = svgRef.current;
    const CTM = svg.getScreenCTM();
    if (!CTM) return null;

    let clientX, clientY;
    if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - CTM.e) / CTM.a,
      y: (clientY - CTM.f) / CTM.d,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 100; // Squared distance threshold
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    if (!currentStroke && tool !== 'eraser') return;
    if (tool === 'eraser' && !('touches' in e) && !(e.buttons === 1)) return; 

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return d;
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <span className="text-xs text-slate-300">Page {pageIndex + 1} / {numPages}</span>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <div className="flex items-center gap-1 ml-2">
                        {COLORS.map(c => (
                            <button 
                              key={c}
                              onClick={() => setColor(c)}
                              className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                            />
                        ))}
                    </div>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {loading ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className="relative w-full h-full flex items-center justify-center touch-none select-none"
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2 } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // 0. Initialize Worker safely (Blob URL to bypass CORS/importScripts issues)
  useEffect(() => {
    // If already set globally, just mark ready
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }

    const setupWorker = async () => {
        try {
            // Fetch worker code as text
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();

            // Create a Blob URL
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            const workerUrl = URL.createObjectURL(blob);

            pdfjs.GlobalWorkerOptions.workerSrc = workerUrl;
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker via Blob, falling back to CDN URL', error);
            // Fallback (might fail if strict CORS)
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };

    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);

        if (loadedSheet && active) {
            setSheet(loadedSheet);
            // Load Annotations
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);

            // Initial Page Count Check (Image Array)
            // If it's a PDF, we update this after PDF loads
            if (loadedSheet.pages.length > 0) {
                 setNumPages(loadedSheet.pages.length);
            }
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL for Current "File"
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;

    const isPdf = sheet.pages[0].fileType === 'application/pdf';

    let activeBlob: Blob;

    if (isPdf) {
        // Always use the first file (the PDF)
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        // Use the file corresponding to current index
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }

    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);

    return () => {
        URL.revokeObjectURL(url);
    };
  }, [sheet, pageIndex]);

  // 3. Load PDF Document (Wait for Worker)
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;

    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                // Ensure pageIndex is valid for new doc
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page to Canvas
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;

    let renderTask: any = null;

    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);

            // Calculate scale to fit container
            const container = containerRef.current;
            if (!container) return;

            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });

            // Determine best fit scale
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98; // 2% margin

            const viewport = page.getViewport({ scale });

            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;

                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };

                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };

    renderPage();

    return () => {
        if (renderTask) renderTask.cancel();
    };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions for SVG ViewBox (Overlay)
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // --- Navigation ---

  const handlePageNext = () => {
    if (pageIndex < numPages - 1) {
        setPageIndex(prev => prev + 1);
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePagePrev = () => {
    if (pageIndex > 0) {
        setPageIndex(prev => prev - 1);
    } else if (hasPrev) {
        onPrev();
    }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') {
        onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);


  // --- Drawing Logic ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    if (!svgRef.current) return null;
    const svg = svgRef.current;
    const CTM = svg.getScreenCTM();
    if (!CTM) return null;

    let clientX, clientY;
    if ('touches' in e) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - CTM.e) / CTM.a,
      y: (clientY - CTM.f) / CTM.d,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 100; // Squared distance threshold
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    if (!currentStroke && tool !== 'eraser') return;
    if (tool === 'eraser' && !('touches' in e) && !(e.buttons === 1)) return; 

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    const d = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return d;
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <span className="text-xs text-slate-300">Page {pageIndex + 1} / {numPages}</span>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <div className="flex items-center gap-1 ml-2">
                        {COLORS.map(c => (
                            <button 
                              key={c}
                              onClick={() => setColor(c)}
                              className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                            />
                        ))}
                    </div>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className="relative w-full h-full flex items-center justify-center touch-none select-none"
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

const CACHE_NAME = 'opusview-v1';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json',
  'https://cdn.tailwindcss.com',
  'https://esm.sh/react@^19.2.1/',
  'https://esm.sh/react@^19.2.1',
  'https://esm.sh/lucide-react@^0.559.0',
  'https://esm.sh/react-dom@^19.2.1/',
  'https://esm.sh/pdfjs-dist@3.11.174',
  'https://esm.sh/pdfjs-dist@3.11.174/',
  'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js'
];

// Install event: cache core assets
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    })
  );
  self.skipWaiting();
});

// Activate event: clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

// Fetch event: Network first, fall back to cache for HTML/API, Cache first for static assets
self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // For external CDNs (modules, tailwind), use Stale-While-Revalidate
  // This ensures fast load but updates eventually
  if (url.hostname === 'cdn.tailwindcss.com' || url.hostname === 'esm.sh' || url.hostname === 'cdn-icons-png.flaticon.com' || url.hostname === 'cdnjs.cloudflare.com') {
    event.respondWith(
      caches.open(CACHE_NAME).then((cache) => {
        return cache.match(event.request).then((cachedResponse) => {
          const fetchPromise = fetch(event.request).then((networkResponse) => {
            cache.put(event.request, networkResponse.clone());
            return networkResponse;
          });
          return cachedResponse || fetchPromise;
        });
      })
    );
    return;
  }

  // For local files, try network first, then cache (to ensure development updates are seen)
  // In a production build, you might want Cache First for hashed assets.
  event.respondWith(
    fetch(event.request)
      .then((response) => {
        // Check if we received a valid response
        if (!response || response.status !== 200 || response.type !== 'basic') {
          return response;
        }
        const responseToCache = response.clone();
        caches.open(CACHE_NAME).then((cache) => {
          cache.put(event.request, responseToCache);
        });
        return response;
      })
      .catch(() => {
        return caches.match(event.request);
      })
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2 } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    const setupWorker = async () => {
        try {
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            pdfjs.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker', error);
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };
    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;
    const isPdf = sheet.pages[0].fileType === 'application/pdf';
    let activeBlob: Blob;
    if (isPdf) {
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }
    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [sheet, pageIndex]);

  // 3. Load PDF Document
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;
    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <span className="text-xs text-slate-300">Page {pageIndex + 1} / {numPages}</span>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <div className="flex items-center gap-1 ml-2">
                        {COLORS.map(c => (
                            <button 
                              key={c}
                              onClick={() => setColor(c)}
                              className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                            />
                        ))}
                    </div>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2, ChevronDown } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Go To Page State
  const [showPageNav, setShowPageNav] = useState(false);
  const [targetPage, setTargetPage] = useState(1);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const pageNavRef = useRef<HTMLDivElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    const setupWorker = async () => {
        try {
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            pdfjs.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker', error);
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };
    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;
    const isPdf = sheet.pages[0].fileType === 'application/pdf';
    let activeBlob: Blob;
    if (isPdf) {
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }
    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [sheet, pageIndex]);

  // 3. Load PDF Document
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;
    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Click outside to close nav
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (pageNavRef.current && !pageNavRef.current.contains(event.target as Node)) {
        setShowPageNav(false);
      }
    };
    if (showPageNav) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showPageNav]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  const handleJumpToPage = (e: React.FormEvent) => {
      e.preventDefault();
      const p = Math.max(1, Math.min(numPages, targetPage));
      setPageIndex(p - 1);
      setShowPageNav(false);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color,
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <div className="relative" ref={pageNavRef}>
                        <button 
                            onClick={() => {
                                setShowPageNav(!showPageNav);
                                setTargetPage(pageIndex + 1);
                            }}
                            className="flex items-center gap-1 text-xs text-slate-300 hover:text-white bg-white/5 px-2 py-1 rounded transition-colors"
                        >
                            <span>Page {pageIndex + 1} / {numPages}</span>
                            <ChevronDown size={12} className={`transition-transform ${showPageNav ? 'rotate-180' : ''}`} />
                        </button>

                        {showPageNav && (
                            <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-64 z-50">
                                <form onSubmit={handleJumpToPage} className="flex flex-col gap-4">
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="text-xs text-slate-400 font-bold uppercase">Go to page</span>
                                        <span className="text-xs text-slate-500">{targetPage} / {numPages}</span>
                                    </div>

                                    <input 
                                        type="range" 
                                        min="1" 
                                        max={numPages} 
                                        value={targetPage}
                                        onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                    />

                                    <div className="flex gap-2">
                                        <input 
                                            type="number" 
                                            min="1" 
                                            max={numPages}
                                            value={targetPage}
                                            onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                            className="flex-1 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-center focus:ring-1 focus:ring-blue-500 outline-none"
                                        />
                                        <button 
                                            type="submit"
                                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded text-sm font-medium"
                                        >
                                            Go
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <div className="flex items-center gap-1 ml-2">
                        {COLORS.map(c => (
                            <button 
                              key={c}
                              onClick={() => setColor(c)}
                              className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                              style={{ backgroundColor: c }}
                            />
                        ))}
                    </div>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && !showPageNav && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && !showPageNav && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2, ChevronDown, Sliders } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

// Helper: Convert Hex to RGBA
const hexToRgba = (hex: string, alpha: number) => {
    let r = 0, g = 0, b = 0;
    if (hex.length === 4) {
      r = parseInt(hex[1] + hex[1], 16);
      g = parseInt(hex[2] + hex[2], 16);
      b = parseInt(hex[3] + hex[3], 16);
    } else if (hex.length === 7) {
      r = parseInt(hex.slice(1, 3), 16);
      g = parseInt(hex.slice(3, 5), 16);
      b = parseInt(hex.slice(5, 7), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Go To Page State
  const [showPageNav, setShowPageNav] = useState(false);
  const [targetPage, setTargetPage] = useState(1);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [opacity, setOpacity] = useState(1);
  const [showPenSettings, setShowPenSettings] = useState(false);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const pageNavRef = useRef<HTMLDivElement>(null);
  const penSettingsRef = useRef<HTMLDivElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    const setupWorker = async () => {
        try {
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            pdfjs.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker', error);
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };
    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;
    const isPdf = sheet.pages[0].fileType === 'application/pdf';
    let activeBlob: Blob;
    if (isPdf) {
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }
    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [sheet, pageIndex]);

  // 3. Load PDF Document
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;
    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Click outside to close navs
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (pageNavRef.current && !pageNavRef.current.contains(event.target as Node)) {
        setShowPageNav(false);
      }
      if (penSettingsRef.current && !penSettingsRef.current.contains(event.target as Node)) {
        setShowPenSettings(false);
      }
    };
    if (showPageNav || showPenSettings) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showPageNav, showPenSettings]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  const handleJumpToPage = (e: React.FormEvent) => {
      e.preventDefault();
      const p = Math.max(1, Math.min(numPages, targetPage));
      setPageIndex(p - 1);
      setShowPageNav(false);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color: hexToRgba(color, opacity),
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav || showPenSettings) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <div className="relative" ref={pageNavRef}>
                        <button 
                            onClick={() => {
                                setShowPageNav(!showPageNav);
                                setTargetPage(pageIndex + 1);
                                setShowPenSettings(false); // Close other popups
                            }}
                            className="flex items-center gap-1 text-xs text-slate-300 hover:text-white bg-white/5 px-2 py-1 rounded transition-colors"
                        >
                            <span>Page {pageIndex + 1} / {numPages}</span>
                            <ChevronDown size={12} className={`transition-transform ${showPageNav ? 'rotate-180' : ''}`} />
                        </button>

                        {showPageNav && (
                            <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-64 z-50">
                                <form onSubmit={handleJumpToPage} className="flex flex-col gap-4">
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="text-xs text-slate-400 font-bold uppercase">Go to page</span>
                                        <span className="text-xs text-slate-500">{targetPage} / {numPages}</span>
                                    </div>

                                    <input 
                                        type="range" 
                                        min="1" 
                                        max={numPages} 
                                        value={targetPage}
                                        onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                    />

                                    <div className="flex gap-2">
                                        <input 
                                            type="number" 
                                            min="1" 
                                            max={numPages}
                                            value={targetPage}
                                            onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                            className="flex-1 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-center focus:ring-1 focus:ring-blue-500 outline-none"
                                        />
                                        <button 
                                            type="submit"
                                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded text-sm font-medium"
                                        >
                                            Go
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <>
                        <div className="flex items-center gap-1 ml-2">
                            {COLORS.map(c => (
                                <button 
                                key={c}
                                onClick={() => setColor(c)}
                                className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                                style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>

                        <div className="h-6 w-px bg-white/20 mx-1" />

                        <div className="relative" ref={penSettingsRef}>
                            <button 
                                onClick={() => {
                                    setShowPenSettings(!showPenSettings);
                                    setShowPageNav(false);
                                }}
                                className={`p-2 rounded-full transition-colors ${showPenSettings ? 'bg-white/20 text-white' : 'text-slate-400 hover:text-white'}`}
                                title="Pen Settings"
                            >
                                <Sliders size={18} />
                            </button>
                            {showPenSettings && (
                                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-56 z-50">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Pen Options</h4>

                                    {/* Preview */}
                                    <div className="bg-slate-900 rounded-lg p-3 mb-4 border border-slate-700/50 flex items-center justify-center">
                                        <svg width="100%" height="30" style={{ overflow: 'visible' }}>
                                            <path 
                                                d="M 10 15 Q 90 5, 170 15" 
                                                stroke={hexToRgba(color, opacity)} 
                                                strokeWidth={lineWidth} 
                                                fill="none" 
                                                strokeLinecap="round"
                                            />
                                        </svg>
                                    </div>

                                    {/* Width Slider */}
                                    <div className="mb-4">
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Width</span>
                                            <span className="text-xs text-slate-300">{lineWidth}px</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="1" 
                                            max="20" 
                                            step="1"
                                            value={lineWidth}
                                            onChange={(e) => setLineWidth(parseInt(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>

                                    {/* Opacity Slider */}
                                    <div>
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Opacity</span>
                                            <span className="text-xs text-slate-300">{Math.round(opacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="0.1" 
                                            max="1.0" 
                                            step="0.1"
                                            value={opacity}
                                            onChange={(e) => setOpacity(parseFloat(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>
                                </div>
                            )}
                        </div>
                    </>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && !showPageNav && !showPenSettings && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && !showPageNav && !showPenSettings && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2, ChevronDown, Sliders } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

// Helper: Convert Hex to RGBA
const hexToRgba = (hex: string, alpha: number) => {
    let r = 0, g = 0, b = 0;
    if (hex.length === 4) {
      r = parseInt(hex[1] + hex[1], 16);
      g = parseInt(hex[2] + hex[2], 16);
      b = parseInt(hex[3] + hex[3], 16);
    } else if (hex.length === 7) {
      r = parseInt(hex.slice(1, 3), 16);
      g = parseInt(hex.slice(3, 5), 16);
      b = parseInt(hex.slice(5, 7), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const Viewer: React.FC<ViewerProps> = ({ sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title }) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // Go To Page State
  const [showPageNav, setShowPageNav] = useState(false);
  const [targetPage, setTargetPage] = useState(1);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [opacity, setOpacity] = useState(1);
  const [showPenSettings, setShowPenSettings] = useState(false);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const pageNavRef = useRef<HTMLDivElement>(null);
  const penSettingsRef = useRef<HTMLDivElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    const setupWorker = async () => {
        try {
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            pdfjs.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker', error);
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };
    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;
    const isPdf = sheet.pages[0].fileType === 'application/pdf';
    let activeBlob: Blob;
    if (isPdf) {
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }
    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [sheet, pageIndex]);

  // 3. Load PDF Document
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;
    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Click outside to close navs
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (pageNavRef.current && !pageNavRef.current.contains(event.target as Node)) {
        setShowPageNav(false);
      }
      if (penSettingsRef.current && !penSettingsRef.current.contains(event.target as Node)) {
        setShowPenSettings(false);
      }
    };
    if (showPageNav || showPenSettings) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showPageNav, showPenSettings]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  const handleJumpToPage = (e: React.FormEvent) => {
      e.preventDefault();
      const p = Math.max(1, Math.min(numPages, targetPage));
      setPageIndex(p - 1);
      setShowPageNav(false);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color: hexToRgba(color, opacity),
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav || showPenSettings) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                {numPages > 1 && (
                    <div className="relative" ref={pageNavRef}>
                        <button 
                            onClick={() => {
                                setShowPageNav(!showPageNav);
                                setTargetPage(pageIndex + 1);
                                setShowPenSettings(false); // Close other popups
                            }}
                            className="flex items-center gap-1 text-xs text-slate-300 hover:text-white bg-white/5 px-2 py-1 rounded transition-colors"
                        >
                            <span>Page {pageIndex + 1} / {numPages}</span>
                            <ChevronDown size={12} className={`transition-transform ${showPageNav ? 'rotate-180' : ''}`} />
                        </button>

                        {showPageNav && (
                            <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-64 z-50">
                                <form onSubmit={handleJumpToPage} className="flex flex-col gap-4">
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="text-xs text-slate-400 font-bold uppercase">Go to page</span>
                                        <span className="text-xs text-slate-500">{targetPage} / {numPages}</span>
                                    </div>

                                    <input 
                                        type="range" 
                                        min="1" 
                                        max={numPages} 
                                        value={targetPage}
                                        onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                    />

                                    <div className="flex gap-2">
                                        <input 
                                            type="number" 
                                            min="1" 
                                            max={numPages}
                                            value={targetPage}
                                            onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                            className="flex-1 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-center focus:ring-1 focus:ring-blue-500 outline-none"
                                        />
                                        <button 
                                            type="submit"
                                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded text-sm font-medium"
                                        >
                                            Go
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <>
                        <div className="flex items-center gap-1 ml-2">
                            {COLORS.map(c => (
                                <button 
                                key={c}
                                onClick={() => setColor(c)}
                                className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                                style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>

                        <div className="h-6 w-px bg-white/20 mx-1" />

                        <div className="relative" ref={penSettingsRef}>
                            <button 
                                onClick={() => {
                                    setShowPenSettings(!showPenSettings);
                                    setShowPageNav(false);
                                }}
                                className={`p-2 rounded-full transition-colors ${showPenSettings ? 'bg-white/20 text-white' : 'text-slate-400 hover:text-white'}`}
                                title="Pen Settings"
                            >
                                <Sliders size={18} />
                            </button>
                            {showPenSettings && (
                                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-56 z-50">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Pen Options</h4>

                                    {/* Preview */}
                                    <div className="bg-slate-900 rounded-lg p-3 mb-4 border border-slate-700/50 flex items-center justify-center overflow-hidden">
                                        <svg width="160" height="40" className="block">
                                            <path 
                                                d="M 20 20 Q 80 5, 140 20" 
                                                stroke={hexToRgba(color, opacity)} 
                                                strokeWidth={lineWidth} 
                                                fill="none" 
                                                strokeLinecap="round"
                                            />
                                        </svg>
                                    </div>

                                    {/* Width Slider */}
                                    <div className="mb-4">
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Width</span>
                                            <span className="text-xs text-slate-300">{lineWidth}px</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="1" 
                                            max="20" 
                                            step="1"
                                            value={lineWidth}
                                            onChange={(e) => setLineWidth(parseInt(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>

                                    {/* Opacity Slider */}
                                    <div>
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Opacity</span>
                                            <span className="text-xs text-slate-300">{Math.round(opacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="0.1" 
                                            max="1.0" 
                                            step="0.1"
                                            value={opacity}
                                            onChange={(e) => setOpacity(parseFloat(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>
                                </div>
                            )}
                        </div>
                    </>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && !showPageNav && !showPenSettings && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && !showPageNav && !showPenSettings && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

