import { DB_NAME, DB_VERSION, STORES, INITIAL_TAGS } from '../constants';
import { Sheet, Setlist, AnnotationLayer, SheetPage, TagDef } from '../types';

class StorageService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => reject(request.error);
      request.onsuccess = () => {
        this.db = request.result;
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        if (!db.objectStoreNames.contains(STORES.SHEETS)) {
          db.createObjectStore(STORES.SHEETS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.SETLISTS)) {
          db.createObjectStore(STORES.SETLISTS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.ANNOTATIONS)) {
          db.createObjectStore(STORES.ANNOTATIONS, { keyPath: 'sheetId' });
        }
        if (!db.objectStoreNames.contains(STORES.TAGS)) {
          const tagStore = db.createObjectStore(STORES.TAGS, { keyPath: 'label' });
          // Populate default tags
          INITIAL_TAGS.forEach(tag => tagStore.add(tag));
        }
      };
    });
  }

  private async transaction<T>(storeName: string, mode: IDBTransactionMode, callback: (store: IDBObjectStore) => IDBRequest | void): Promise<T> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const tx = this.db!.transaction(storeName, mode);
      const store = tx.objectStore(storeName);
      let request: IDBRequest | void;

      try {
        request = callback(store);
      } catch (e) {
        reject(e);
        return;
      }

      tx.oncomplete = () => resolve(request ? request.result : undefined);
      tx.onerror = () => reject(tx.error);
    });
  }

  // --- Sheets ---

  async addSheet(sheet: Sheet): Promise<void> {
    // We store the pages directly in IDB (blobs are supported)
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(sheet));
  }

  async updateSheetMetadata(sheet: Sheet): Promise<void> {
    const existing = await this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(sheet.id));
    if (!existing) throw new Error('Sheet not found');

    // Preserve pages, update metadata (name, tags, tagIcons)
    const record: Sheet = { 
      ...existing, 
      name: sheet.name, 
      tags: sheet.tags,
      tagIcons: sheet.tagIcons // Persist the custom icon map
    };
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(record));
  }

  async getAllSheets(): Promise<Sheet[]> {
    // Fetches metadata + blobs. 
    // Optimization: In a real app we might store blobs in a separate store to keep listing fast, 
    // but for IndexedDB local app, fetching all is usually acceptable for < 100mb data.
    return this.transaction(STORES.SHEETS, 'readonly', (store) => store.getAll());
  }

  async getSheet(id: string): Promise<Sheet | undefined> {
    return this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(id));
  }

  async deleteSheet(id: string): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.delete(id));
    await this.deleteAnnotation(id);
  }

  // --- Setlists ---

  async saveSetlist(setlist: Setlist): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.put(setlist));
  }

  async getAllSetlists(): Promise<Setlist[]> {
    return this.transaction(STORES.SETLISTS, 'readonly', (store) => store.getAll());
  }

  async deleteSetlist(id: string): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.delete(id));
  }

  // --- Annotations ---

  async saveAnnotation(sheetId: string, strokes: any[]): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.put({ sheetId, strokes }));
  }

  async getAnnotation(sheetId: string): Promise<AnnotationLayer | undefined> {
    return this.transaction(STORES.ANNOTATIONS, 'readonly', (store) => store.get(sheetId));
  }

  async deleteAnnotation(sheetId: string): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.delete(sheetId));
  }

  // --- Tags ---

  async getAllTags(): Promise<TagDef[]> {
    return this.transaction(STORES.TAGS, 'readonly', (store) => store.getAll());
  }

  async saveTag(tag: TagDef): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.put(tag));
  }

  async deleteTag(label: string): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.delete(label));
  }
}

export const storage = new StorageService();

import React, { useRef, useState, useMemo, useEffect } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown } from 'lucide-react';
import { Sheet, SheetPage, TagDef } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';

interface LibraryProps {
  sheets: Sheet[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

const Library: React.FC<LibraryProps> = ({ sheets, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, []);

  const loadTags = async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  };

  // Handle individual files (Legacy behavior + Single file uploads)
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        await storage.addSheet(newSheet);
      }
      onRefresh();
    }
  };

  // Handle Folder Upload (Group by directory)
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files);
      // Group files by top-level folder name (or parent folder name)
      const groups: Record<string, File[]> = {};

      files.forEach(file => {
        // webkitRelativePath is usually "FolderName/FileName.png"
        const pathParts = file.webkitRelativePath.split('/');
        // If it's in a folder, use folder name, otherwise use filename base
        const groupName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Unsorted";

        if (!groups[groupName]) groups[groupName] = [];
        if (file.type.startsWith('image/') || file.type === 'application/pdf') {
             groups[groupName].push(file);
        }
      });

      for (const [name, groupFiles] of Object.entries(groups)) {
        // Sort files by name to ensure page order (page1, page2...)
        groupFiles.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

        const pages: SheetPage[] = groupFiles.map(f => ({
            blob: f,
            fileType: f.type as any
        }));

        const newSheet: Sheet = {
            id: crypto.randomUUID(),
            name: name,
            tags: [],
            dateAdded: Date.now(),
            pages: pages
        };
        await storage.addSheet(newSheet);
      }
      onRefresh();
    }
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Are you sure you want to delete this sheet?')) {
      await storage.deleteSheet(id);
      onRefresh();
    }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName); // Add to current sheet

      // Add to global Quick Add list
      const iconName = selectedIconName || 'Tag';
      await storage.saveTag({ label: tagName, iconName });
      await loadTags(); // Refresh list

      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const handleDeleteGlobalTag = async (e: React.MouseEvent, label: string) => {
      e.stopPropagation();
      if (confirm(`Remove "${label}" from Quick Add list?`)) {
          await storage.deleteTag(label);
          await loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      setEditingSheet(null);
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  // Resolve which icon component to use for a given tag
  const getTagIcon = (tag: string, sheet?: Sheet) => {
    // 1. Check specific sheet overrides (if provided)
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    // 2. Check edit session overrides (for the modal)
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    // 3. Check global presets
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;

    // 4. Fallback
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex gap-3 items-start w-full md:w-auto">
            <div className="relative flex-1 md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 shrink-0">
                <button 
                    onClick={() => folderInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 w-full"
                    title="Import a folder containing multiple pages"
                >
                    <FolderUp size={20} />
                    <span className="hidden sm:inline">Folder</span>
                </button>

                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 w-full"
                >
                    <Upload size={20} />
                    <span className="hidden sm:inline">File</span>
                </button>
            </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
        {/* Directory Input */}
        <input 
            type="file"
            ref={folderInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleFolderChange}
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';

             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    {isPdf ? (
                        <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                    ) : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDelete(e, sheet.id)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setEditingSheet(null)}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={() => setEditingSheet(null)} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
