                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>
                                        <button 
                                            onClick={(e) => handleDeleteGlobalTag(e, tagDef.label)}
                                            className="absolute -top-1 -right-1 bg-slate-950 text-slate-400 rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity border border-slate-700 hover:text-red-500 z-10"
                                            title="Delete from Quick Add"
                                        >
                                            <X size={10} />
                                        </button>
                                    </div>
                                  )
