                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                                // Removed onKeyDown to enforce button usage as requested
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import { Sheet, SheetPage } from '../types';

interface ProcessResult {
  sheets: Sheet[];
  setlistName?: string;
  error?: string;
}

export const processBatchImport = async (fileList: FileList): Promise<ProcessResult> => {
  const files = Array.from(fileList).filter(f => !f.name.startsWith('.')); // Ignore hidden files

  if (files.length === 0) return { sheets: [] };

  // 1. Structure Verification
  // Expected: Root/File.pdf OR Root/Folder/Image.png
  // Invalid: Root/Folder/Nested/Image.png

  const rootFolderName = files[0].webkitRelativePath.split('/')[0];
  const groupedFiles = new Map<string, File[]>();
  const rootFiles: File[] = [];

  for (const file of files) {
    const parts = file.webkitRelativePath.split('/');

    // Safety check for path depth
    // parts[0] = Root
    // parts[1] = File (if length 2) OR Folder (if length 3)
    // parts[2] = File (if length 3)

    if (parts.length > 3) {
      return { sheets: [], error: `Invalid structure in "${file.webkitRelativePath}". Nested folders are not allowed.` };
    }

    if (parts.length === 2) {
      // It's a file in the root
      rootFiles.push(file);
    } else if (parts.length === 3) {
      // It's a file in a subfolder (a piece)
      const folderName = parts[1];
      if (!groupedFiles.has(folderName)) {
        groupedFiles.set(folderName, []);
      }
      groupedFiles.get(folderName)!.push(file);
    }
  }

  const resultSheets: Sheet[] = [];

  // 2. Process Root Files (PDFs or Images acting as single page sheets)
  for (const file of rootFiles) {
     const name = file.name.replace(/\.[^/.]+$/, "");
     const page: SheetPage = {
         blob: file,
         fileType: file.type as any
     };

     // Construct Sheet
     resultSheets.push({
         id: crypto.randomUUID(),
         name: name,
         tags: [],
         dateAdded: Date.now(),
         pages: [page]
     });
  }

  // 3. Process Grouped Folders (Multi-page sheets)
  for (const [folderName, groupFiles] of groupedFiles.entries()) {
      // Sort files by name (e.g. page1, page2)
      // We use numeric sort for "page1", "page10" handling if possible, or simple localeCompare
      groupFiles.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      // Validate: Folders should primarily contain images. 
      // If a folder contains a PDF, current Viewer expects 1 PDF per sheet. 
      // We will allow it but warn or fail if mixed? 
      // User prompt implies: "pngFolder: page1.png, page2.png". 
      // We'll assume folder = multi-page image sheet.
      // If a PDF is found inside a folder, we treat it as a page, but Viewer might struggle if mixed.
      // For safety based on prompt, we assume standard usage.

      const pages: SheetPage[] = groupFiles.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      resultSheets.push({
          id: crypto.randomUUID(),
          name: folderName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      });
  }

  return { sheets: resultSheets, setlistName: rootFolderName };
};

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon } from 'lucide-react';
import { Sheet, SheetPage, TagDef } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

const Library: React.FC<LibraryProps> = ({ sheets, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        await storage.addSheet(newSheet);
      }
      onRefresh();
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import (Legacy/Standard: Folder = One Sheet)
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      // Sort files by name
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      // Use the parent folder name as the sheet name
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await storage.addSheet(newSheet);
      onRefresh();
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import (Structure Verified)
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            let count = 0;
            for (const sheet of result.sheets) {
                await storage.addSheet(sheet);
                count++;
            }
            alert(`Successfully imported ${count} entries.`);
            onRefresh();
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Are you sure you want to delete this sheet?')) {
      await storage.deleteSheet(id);
      onRefresh();
    }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName); // Add to current sheet

      // Add to global Quick Add list (Optimistic Update)
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };

      const tagExists = allTags.some(t => t.label === tagName);

      if (!tagExists) {
          // Optimistic update
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);

          try {
            await storage.saveTag(newTagDef);
            // Verify sync
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            // Revert
            await loadTags();
          }
      }

      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      // 1. Optimistic Update: Immediately filter out the tag from local state
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);

      try {
        // 2. Perform DB deletion
        await storage.deleteTag(label);

        // 3. Ensure sync (fetch latest from DB to be sure)
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        // On error, reload to restore state
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  // Resolve which icon component to use for a given tag
  const getTagIcon = (tag: string, sheet?: Sheet) => {
    // 1. Check specific sheet overrides (if provided)
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    // 2. Check edit session overrides (for the modal)
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    // 3. Check global presets
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;

    // 4. Fallback
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <button 
                    onClick={() => folderInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                    title="Import a folder containing pages as ONE sheet"
                >
                    <FolderUp size={20} />
                    <span className="hidden sm:inline">Folder (Sheet)</span>
                </button>

                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                >
                    <Upload size={20} />
                    <span className="hidden sm:inline">File</span>
                </button>
            </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
        {/* Single Sheet Folder Input */}
        <input 
            type="file"
            ref={folderInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleFolderChange}
        />
        {/* Batch Import Input */}
        <input 
            type="file"
            ref={batchInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleBatchImport}
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';

             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    {isPdf ? (
                        <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                    ) : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDelete(e, sheet.id)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={closeEditModal}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this setlist?')) {
        await storage.deleteSetlist(id);
        onRefresh();
    }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            const newSheetIds: string[] = [];

            // 1. Save all imported sheets to Library
            for (const sheet of result.sheets) {
                await storage.addSheet(sheet);
                newSheetIds.push(sheet.id);
            }

            // 2. Create new Setlist ordered by name (result.sheets is not guaranteed sorted by name in processor? 
            // The processor output order depends on Map iteration which is insertion order. 
            // We should sort the sheets by name before creating the setlist as requested.

            result.sheets.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
            const sortedIds = result.sheets.map(s => s.id);

            const setlistName = result.setlistName || "Imported Setlist";

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: setlistName,
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);

            alert(`Imported ${result.sheets.length} sheets and created setlist "${setlistName}".`);
            onRefresh();
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
