      queue: setlist.sheetIds,
      currentIndex: 0
    });
    setView(AppView.VIEWER);
  };

  const handleNext = () => {
    if (!viewerState) return;
    if (viewerState.currentIndex < viewerState.queue.length - 1) {
      setViewerState({ ...viewerState, currentIndex: viewerState.currentIndex + 1 });
    }
  };

  const handlePrev = () => {
    if (!viewerState) return;
    if (viewerState.currentIndex > 0) {
      setViewerState({ ...viewerState, currentIndex: viewerState.currentIndex - 1 });
    }
  };

  const handleJumpTo = (index: number) => {
    if (!viewerState) return;
    if (index >= 0 && index < viewerState.queue.length) {
        setViewerState({ ...viewerState, currentIndex: index });
    }
  };

  const closeViewer = () => {
    setViewerState(null);
    setView(previousView);
  };

  // Get current sheet title for viewer
  const getCurrentSheetTitle = () => {
    if (!viewerState) return '';
    const currentId = viewerState.queue[viewerState.currentIndex];
    const sheet = sheets.find(s => s.id === currentId);
    return sheet ? sheet.name : 'Unknown';
  };

  if (view === AppView.VIEWER && viewerState) {
    const currentSheetId = viewerState.queue[viewerState.currentIndex];

    // Prepare queue data for the Viewer's dropdown
    const queueData = viewerState.queue.map(id => {
        const s = sheets.find(sheet => sheet.id === id);
        return { id, name: s ? s.name : 'Unknown Sheet' };
    });

    return (
      <Viewer 
        sheetId={currentSheetId}
        title={getCurrentSheetTitle()}
        onClose={closeViewer}
        onNext={handleNext}
        onPrev={handlePrev}
        hasNext={viewerState.currentIndex < viewerState.queue.length - 1}
        hasPrev={viewerState.currentIndex > 0}
        queue={queueData}
        currentQueueIndex={viewerState.currentIndex}
        onJumpTo={handleJumpTo}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-900 text-slate-100 font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-20 md:w-64 bg-slate-950 border-r border-slate-800 flex flex-col justify-between z-10">
        <div>
          <div className="p-6 flex items-center gap-3">
             <div className="w-8 h-8 bg-gradient-to-tr from-blue-600 to-purple-500 rounded-lg flex items-center justify-center shrink-0">
               <Music size={18} className="text-white" />
             </div>
             <span className="font-bold text-xl hidden md:block tracking-tight">OpusView</span>
          </div>

          <div className="mt-6 px-3 space-y-2">
            <button 
              onClick={() => setView(AppView.LIBRARY)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${view === AppView.LIBRARY ? 'bg-blue-600/10 text-blue-400' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-900'}`}
            >
              <Music size={22} />
              <span className="font-medium hidden md:block">Library</span>
            </button>
            <button 
              onClick={() => setView(AppView.SETLISTS)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${view === AppView.SETLISTS ? 'bg-blue-600/10 text-blue-400' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-900'}`}
            >
              <ListMusic size={22} />
              <span className="font-medium hidden md:block">Setlists</span>
            </button>
          </div>
        </div>

        <div className="p-6 border-t border-slate-800">
          <div className="flex items-center gap-4 text-slate-500">
             <Settings size={20} />
             <span className="text-sm hidden md:block">v1.0.0</span>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto no-scrollbar relative bg-gradient-to-br from-slate-900 to-slate-800">
        {view === AppView.LIBRARY && (
          <Library 
            sheets={sheets}
            setlists={setlists}
            onImport={() => {}} // Handled inside component
            onRefresh={loadData}
            onSelect={openViewer}
          />
        )}
        {view === AppView.SETLISTS && (
          <Setlists 
            setlists={setlists}
            sheets={sheets}
            onRefresh={loadData}
            onPlay={playSetlist}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2, ChevronDown, Sliders, List } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

// Helper: Convert Hex to RGBA
const hexToRgba = (hex: string, alpha: number) => {
    let r = 0, g = 0, b = 0;
    if (hex.length === 4) {
      r = parseInt(hex[1] + hex[1], 16);
      g = parseInt(hex[2] + hex[2], 16);
      b = parseInt(hex[3] + hex[3], 16);
    } else if (hex.length === 7) {
      r = parseInt(hex.slice(1, 3), 16);
      g = parseInt(hex.slice(3, 5), 16);
      b = parseInt(hex.slice(5, 7), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo 
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // UI States
  const [showPageNav, setShowPageNav] = useState(false);
  const [targetPage, setTargetPage] = useState(1);
  const [showQueueMenu, setShowQueueMenu] = useState(false);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [opacity, setOpacity] = useState(1);
  const [showPenSettings, setShowPenSettings] = useState(false);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const pageNavRef = useRef<HTMLDivElement>(null);
  const penSettingsRef = useRef<HTMLDivElement>(null);
  const queueMenuRef = useRef<HTMLDivElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    const setupWorker = async () => {
        try {
            const response = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js');
            if (!response.ok) throw new Error('Network response was not ok');
            const workerScript = await response.text();
            const blob = new Blob([workerScript], { type: 'text/javascript' });
            pdfjs.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
            setWorkerReady(true);
        } catch (error) {
            console.error('Failed to load PDF worker', error);
            pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
            setWorkerReady(true);
        }
    };
    setupWorker();
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
      } finally {
        if (active) setLoading(false);
      }
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;
    const isPdf = sheet.pages[0].fileType === 'application/pdf';
    let activeBlob: Blob;
    if (isPdf) {
        activeBlob = sheet.pages[0].blob;
        setFileType('application/pdf');
    } else {
        activeBlob = sheet.pages[pageIndex].blob;
        setFileType(sheet.pages[pageIndex].fileType);
    }
    const url = URL.createObjectURL(activeBlob);
    setBlobUrl(url);
    return () => URL.revokeObjectURL(url);
  }, [sheet, pageIndex]);

  // 3. Load PDF Document
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !blobUrl) return;
    let active = true;
    const loadPdf = async () => {
        try {
            const loadingTask = pdfjs.getDocument(blobUrl);
            const doc = await loadingTask.promise;
            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                if (pageIndex >= doc.numPages) setPageIndex(0);
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [blobUrl, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Click outside to close navs
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (pageNavRef.current && !pageNavRef.current.contains(event.target as Node)) {
        setShowPageNav(false);
      }
      if (penSettingsRef.current && !penSettingsRef.current.contains(event.target as Node)) {
        setShowPenSettings(false);
      }
      if (queueMenuRef.current && !queueMenuRef.current.contains(event.target as Node)) {
        setShowQueueMenu(false);
      }
    };
    if (showPageNav || showPenSettings || showQueueMenu) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showPageNav, showPenSettings, showQueueMenu]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  const handleJumpToPage = (e: React.FormEvent) => {
      e.preventDefault();
      const p = Math.max(1, Math.min(numPages, targetPage));
      setPageIndex(p - 1);
      setShowPageNav(false);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color: hexToRgba(color, opacity),
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav || showPenSettings || showQueueMenu) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                    {queue && queue.length > 1 && (
                        <div className="relative" ref={queueMenuRef}>
                            <button
                                onClick={() => {
                                    setShowQueueMenu(!showQueueMenu);
                                    setShowPageNav(false);
                                    setShowPenSettings(false);
                                }}
                                className={`p-1.5 rounded-full transition-colors ${showQueueMenu ? 'bg-white/20 text-white' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                                title="Setlist Queue"
                            >
                                <List size={18} />
                            </button>
                            {showQueueMenu && (
                                <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl w-72 max-h-[60vh] overflow-y-auto z-50 flex flex-col py-1">
                                    {queue.map((item, idx) => (
                                        <button
                                            key={`${item.id}-${idx}`}
                                            onClick={() => {
                                                onJumpTo?.(idx);
                                                setShowQueueMenu(false);
                                            }}
                                            className={`text-left px-4 py-3 text-sm border-b border-slate-700/50 last:border-0 hover:bg-slate-700 transition-colors ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-300 font-medium border-l-2 border-l-blue-500' : 'text-slate-300'}`}
                                        >
                                            <div className="flex gap-3">
                                                <span className="opacity-50 w-5 text-right font-mono">{idx + 1}.</span>
                                                <span className="truncate">{item.name}</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {numPages > 1 && (
                    <div className="relative" ref={pageNavRef}>
                        <button 
                            onClick={() => {
                                setShowPageNav(!showPageNav);
                                setTargetPage(pageIndex + 1);
                                setShowPenSettings(false); // Close other popups
                                setShowQueueMenu(false);
                            }}
                            className="flex items-center gap-1 text-xs text-slate-300 hover:text-white bg-white/5 px-2 py-1 rounded transition-colors mt-0.5"
                        >
                            <span>Page {pageIndex + 1} / {numPages}</span>
                            <ChevronDown size={12} className={`transition-transform ${showPageNav ? 'rotate-180' : ''}`} />
                        </button>

                        {showPageNav && (
                            <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-64 z-50">
                                <form onSubmit={handleJumpToPage} className="flex flex-col gap-4">
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="text-xs text-slate-400 font-bold uppercase">Go to page</span>
                                        <span className="text-xs text-slate-500">{targetPage} / {numPages}</span>
                                    </div>

                                    <input 
                                        type="range" 
                                        min="1" 
                                        max={numPages} 
                                        value={targetPage}
                                        onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                    />

                                    <div className="flex gap-2">
                                        <input 
                                            type="number" 
                                            min="1" 
                                            max={numPages}
                                            value={targetPage}
                                            onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                            className="flex-1 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-center focus:ring-1 focus:ring-blue-500 outline-none"
                                        />
                                        <button 
                                            type="submit"
                                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded text-sm font-medium"
                                        >
                                            Go
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <>
                        <div className="flex items-center gap-1 ml-2">
                            {COLORS.map(c => (
                                <button 
                                key={c}
                                onClick={() => setColor(c)}
                                className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                                style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>

                        <div className="h-6 w-px bg-white/20 mx-1" />

                        <div className="relative" ref={penSettingsRef}>
                            <button 
                                onClick={() => {
                                    setShowPenSettings(!showPenSettings);
                                    setShowPageNav(false);
                                }}
                                className={`p-2 rounded-full transition-colors ${showPenSettings ? 'bg-white/20 text-white' : 'text-slate-400 hover:text-white'}`}
                                title="Pen Settings"
                            >
                                <Sliders size={18} />
                            </button>
                            {showPenSettings && (
                                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-56 z-50">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Pen Options</h4>

                                    {/* Preview */}
                                    <div className="bg-slate-900 rounded-lg p-3 mb-4 border border-slate-700/50 flex items-center justify-center overflow-hidden">
                                        <svg width="160" height="40" className="block">
                                            <path 
                                                d="M 20 20 Q 80 5, 140 20" 
                                                stroke={hexToRgba(color, opacity)} 
                                                strokeWidth={lineWidth} 
                                                fill="none" 
                                                strokeLinecap="round"
                                            />
                                        </svg>
                                    </div>

                                    {/* Width Slider */}
                                    <div className="mb-4">
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Width</span>
                                            <span className="text-xs text-slate-300">{lineWidth}px</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="1" 
                                            max="20" 
                                            step="1"
                                            value={lineWidth}
                                            onChange={(e) => setLineWidth(parseInt(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>

                                    {/* Opacity Slider */}
                                    <div>
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Opacity</span>
                                            <span className="text-xs text-slate-300">{Math.round(opacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="0.1" 
                                            max="1.0" 
                                            step="0.1"
                                            value={opacity}
                                            onChange={(e) => setOpacity(parseFloat(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>
                                </div>
                            )}
                        </div>
                    </>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : blobUrl ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && !showPageNav && !showPenSettings && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && !showPageNav && !showPenSettings && !showQueueMenu && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, PenTool, Eraser, Undo, X, Settings2, Trash2, ChevronDown, Sliders, List } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export structure if present (fixes common issue with cdn imports of pdfjs)
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
}

// Helper: Squared distance between two points
const dist2 = (p1: Point, p2: Point) => (p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2;

// Helper: Minimum squared distance from point P to segment AB
const distToSegmentSquared = (p: Point, a: Point, b: Point) => {
  const l2 = dist2(a, b);
  if (l2 === 0) return dist2(p, a);
  let t = ((p.x - a.x) * (b.x - a.x) + (p.y - a.y) * (b.y - a.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  return dist2(p, { x: a.x + t * (b.x - a.x), y: a.y + t * (b.y - a.y) });
};

// Helper: Convert Hex to RGBA
const hexToRgba = (hex: string, alpha: number) => {
    let r = 0, g = 0, b = 0;
    if (hex.length === 4) {
      r = parseInt(hex[1] + hex[1], 16);
      g = parseInt(hex[2] + hex[2], 16);
      b = parseInt(hex[3] + hex[3], 16);
    } else if (hex.length === 7) {
      r = parseInt(hex.slice(1, 3), 16);
      g = parseInt(hex.slice(3, 5), 16);
      b = parseInt(hex.slice(5, 7), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo 
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);

  // State for Navigation within a single Sheet (e.g. PDF pages or multiple image files)
  const [pageIndex, setPageIndex] = useState(0); 
  const [numPages, setNumPages] = useState(0);

  // UI States
  const [showPageNav, setShowPageNav] = useState(false);
  const [targetPage, setTargetPage] = useState(1);
  const [showQueueMenu, setShowQueueMenu] = useState(false);

  // Content Loading State
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [fileType, setFileType] = useState<string>('');
  const [pdfDoc, setPdfDoc] = useState<any>(null); // PDFDocumentProxy
  const [loading, setLoading] = useState(true);

  // Worker State
  const [workerReady, setWorkerReady] = useState(false);

  // Annotation State
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [currentStroke, setCurrentStroke] = useState<Stroke | null>(null);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [color, setColor] = useState(COLORS[0]);
  const [lineWidth, setLineWidth] = useState(3);
  const [opacity, setOpacity] = useState(1);
  const [showPenSettings, setShowPenSettings] = useState(false);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  // Refs
  const svgRef = useRef<SVGSVGElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const pageNavRef = useRef<HTMLDivElement>(null);
  const penSettingsRef = useRef<HTMLDivElement>(null);
  const queueMenuRef = useRef<HTMLDivElement>(null);

  // 0. Initialize Worker safely
  useEffect(() => {
    if (pdfjs.GlobalWorkerOptions.workerSrc) {
        setWorkerReady(true);
        return;
    }
    // Set worker directly to CDN to avoid blob/fetch issues
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // 1. Load Sheet Data & Annotations
  useEffect(() => {
    let active = true;
    const loadSheet = async () => {
      setLoading(true);
      setPageIndex(0); 
      setPdfDoc(null);
      setNumPages(0);
      try {
        const loadedSheet = await storage.getSheet(sheetId);
        if (loadedSheet && active) {
            setSheet(loadedSheet);
            const storedAnnotations = await storage.getAnnotation(sheetId);
            setAllStrokes(storedAnnotations ? storedAnnotations.strokes : []);
            if (loadedSheet.pages.length > 0) setNumPages(loadedSheet.pages.length);
        }
      } catch (err) {
        console.error("Error loading sheet:", err);
        if (active) setLoading(false);
      }
      // Note: We keep loading true if it's a PDF, forcing the PDF loader to handle the false state
      // If it's not a PDF, we might need to toggle it off here or in the blob effect.
      // For simplicity, we'll let the specific loaders handle the final false state.
    };
    loadSheet();
    return () => { active = false; };
  }, [sheetId]);

  // 2. Prepare Blob URL (Only for Images)
  useEffect(() => {
    if (!sheet || !sheet.pages || sheet.pages.length === 0) return;

    const firstPage = sheet.pages[0];
    const isPdf = firstPage.fileType === 'application/pdf';
    setFileType(isPdf ? 'application/pdf' : sheet.pages[pageIndex].fileType);

    if (!isPdf) {
        // Handle Image
        const activeBlob = sheet.pages[pageIndex].blob;
        const url = URL.createObjectURL(activeBlob);
        setBlobUrl(url);
        setLoading(false); // Images are ready once URL is created
        return () => URL.revokeObjectURL(url);
    } else {
        setBlobUrl(null);
    }
  }, [sheet, pageIndex]);

  // 3. Load PDF Document (Using ArrayBuffer to avoid XHR/Blob URL errors)
  useEffect(() => {
    if (!workerReady || fileType !== 'application/pdf' || !sheet) return;
    let active = true;

    const loadPdf = async () => {
        setLoading(true);
        try {
            // Convert Blob to ArrayBuffer
            const blob = sheet.pages[0].blob;
            const arrayBuffer = await blob.arrayBuffer();

            if (!active) return;

            const loadingTask = pdfjs.getDocument({
                data: new Uint8Array(arrayBuffer),
                cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
                cMapPacked: true,
            });

            const doc = await loadingTask.promise;

            if (active) {
                setPdfDoc(doc);
                setNumPages(doc.numPages);
                setPageIndex(prev => (prev >= doc.numPages ? 0 : prev));
            }
        } catch (error) {
            console.error("Error loading PDF", error);
        } finally {
            if (active) setLoading(false);
        }
    };
    loadPdf();
    return () => { active = false; };
  }, [sheet, fileType, workerReady]); 

  // 4. Render PDF Page
  useEffect(() => {
    if (fileType !== 'application/pdf' || !pdfDoc || !pdfCanvasRef.current) return;
    let renderTask: any = null;
    const renderPage = async () => {
        try {
            const pageNumber = pageIndex + 1;
            const page = await pdfDoc.getPage(pageNumber);
            const container = containerRef.current;
            if (!container) return;
            const { clientWidth, clientHeight } = container;
            const unscaledViewport = page.getViewport({ scale: 1 });
            const scaleX = clientWidth / unscaledViewport.width;
            const scaleY = clientHeight / unscaledViewport.height;
            const scale = Math.min(scaleX, scaleY) * 0.98;
            const viewport = page.getViewport({ scale });
            const canvas = pdfCanvasRef.current;
            if (canvas) {
                canvas.height = viewport.height;
                canvas.width = viewport.width;
                const renderContext = {
                    canvasContext: canvas.getContext('2d')!,
                    viewport: viewport,
                };
                renderTask = page.render(renderContext);
                await renderTask.promise;
            }
        } catch (error: any) {
            if (error.name !== 'RenderingCancelledException') {
                console.error("PDF Render Error", error);
            }
        }
    };
    renderPage();
    return () => { if (renderTask) renderTask.cancel(); };
  }, [pdfDoc, pageIndex, fileType, dimensions]);

  // Sync dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const { clientWidth, clientHeight } = containerRef.current;
        setDimensions({ width: clientWidth, height: clientHeight });
      }
    };
    updateDimensions();
    const resizeObserver = new ResizeObserver(updateDimensions);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [loading, blobUrl]);

  // Save Annotations
  useEffect(() => {
    if (!loading && sheet) {
      const timeout = setTimeout(() => {
        storage.saveAnnotation(sheet.id, allStrokes);
      }, 500); 
      return () => clearTimeout(timeout);
    }
  }, [allStrokes, sheet, loading]);

  // Click outside to close navs
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (pageNavRef.current && !pageNavRef.current.contains(event.target as Node)) {
        setShowPageNav(false);
      }
      if (penSettingsRef.current && !penSettingsRef.current.contains(event.target as Node)) {
        setShowPenSettings(false);
      }
      if (queueMenuRef.current && !queueMenuRef.current.contains(event.target as Node)) {
        setShowQueueMenu(false);
      }
    };
    if (showPageNav || showPenSettings || showQueueMenu) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showPageNav, showPenSettings, showQueueMenu]);

  // Navigation Handlers
  const handlePageNext = () => {
    if (pageIndex < numPages - 1) setPageIndex(prev => prev + 1);
    else if (hasNext) onNext();
  };
  const handlePagePrev = () => {
    if (pageIndex > 0) setPageIndex(prev => prev - 1);
    else if (hasPrev) onPrev();
  };

  const handleJumpToPage = (e: React.FormEvent) => {
      e.preventDefault();
      const p = Math.max(1, Math.min(numPages, targetPage));
      setPageIndex(p - 1);
      setShowPageNav(false);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        e.preventDefault();
        handlePageNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        e.preventDefault();
        handlePagePrev();
      } else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handlePageNext, handlePagePrev, onClose]);

  // --- Drawing Logic Updated ---

  const getPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    // Robust coordinate calculation using getBoundingClientRect
    const container = containerRef.current;
    if (!container) return null;

    const rect = container.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    } else if ('changedTouches' in e && e.changedTouches.length > 0) {
        clientX = e.changedTouches[0].clientX;
        clientY = e.changedTouches[0].clientY;
    } else if ('clientX' in e) {
        clientX = (e as React.MouseEvent).clientX;
        clientY = (e as React.MouseEvent).clientY;
    } else {
        return null;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  };

  const eraseAt = (point: Point) => {
    const threshold = 200; // Increased threshold for easier erasing
    setAllStrokes(prev => prev.filter(stroke => {
      if (stroke.pageIndex !== pageIndex) return true;
      for (let i = 0; i < stroke.points.length - 1; i++) {
        if (distToSegmentSquared(point, stroke.points[i], stroke.points[i + 1]) < threshold) {
          return false;
        }
      }
      return true;
    }));
  };

  const handlePointerDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else {
      setCurrentStroke({
        points: [point],
        color: hexToRgba(color, opacity),
        width: lineWidth,
        pageIndex: pageIndex
      });
    }
  };

  const handlePointerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawingMode) return;

    // Allow erasing without dragging if it's a click, but for drag erase need buttons
    if (!currentStroke && tool !== 'eraser') return;

    // Check for mouse button pressed for erasing
    if (tool === 'eraser' && !('touches' in e) && e.buttons !== 1) return;

    e.preventDefault(); 
    const point = getPoint(e);
    if (!point) return;

    if (tool === 'eraser') {
      eraseAt(point);
    } else if (currentStroke) {
      setCurrentStroke(prev => prev ? {
        ...prev,
        points: [...prev.points, point]
      } : null);
    }
  };

  const handlePointerUp = () => {
    if (currentStroke) {
      setAllStrokes(prev => [...prev, currentStroke]);
      setCurrentStroke(null);
    }
  };

  const handleUndo = () => {
    const currentStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);
    const otherStrokes = allStrokes.filter(s => s.pageIndex !== pageIndex);
    if (currentStrokes.length > 0) {
        setAllStrokes([...otherStrokes, ...currentStrokes.slice(0, -1)]);
    }
  };

  const handleClear = () => {
    if (confirm('Clear annotations on this page?')) {
        setAllStrokes(prev => prev.filter(s => s.pageIndex !== pageIndex));
    }
  };

  const getSvgPath = (points: Point[]) => {
    if (points.length === 0) return '';
    // SVG Path with quadratic Bezier curves for smoothing could be added here
    // For now, straight lines are reliable
    return points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
  };

  const visibleStrokes = allStrokes.filter(s => s.pageIndex === pageIndex);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-20 flex justify-between items-center p-4 bg-gradient-to-b from-black/80 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav || showPenSettings || showQueueMenu) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white">
                <X size={20} />
            </button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-medium truncate max-w-[200px] sm:max-w-md shadow-sm">{title}</h2>
                    {queue && queue.length > 1 && (
                        <div className="relative" ref={queueMenuRef}>
                            <button
                                onClick={() => {
                                    setShowQueueMenu(!showQueueMenu);
                                    setShowPageNav(false);
                                    setShowPenSettings(false);
                                }}
                                className={`p-1.5 rounded-full transition-colors ${showQueueMenu ? 'bg-white/20 text-white' : 'text-slate-300 hover:text-white hover:bg-white/10'}`}
                                title="Setlist Queue"
                            >
                                <List size={18} />
                            </button>
                            {showQueueMenu && (
                                <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl w-72 max-h-[60vh] overflow-y-auto z-50 flex flex-col py-1">
                                    {queue.map((item, idx) => (
                                        <button
                                            key={`${item.id}-${idx}`}
                                            onClick={() => {
                                                onJumpTo?.(idx);
                                                setShowQueueMenu(false);
                                            }}
                                            className={`text-left px-4 py-3 text-sm border-b border-slate-700/50 last:border-0 hover:bg-slate-700 transition-colors ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-300 font-medium border-l-2 border-l-blue-500' : 'text-slate-300'}`}
                                        >
                                            <div className="flex gap-3">
                                                <span className="opacity-50 w-5 text-right font-mono">{idx + 1}.</span>
                                                <span className="truncate">{item.name}</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {numPages > 1 && (
                    <div className="relative" ref={pageNavRef}>
                        <button 
                            onClick={() => {
                                setShowPageNav(!showPageNav);
                                setTargetPage(pageIndex + 1);
                                setShowPenSettings(false); // Close other popups
                                setShowQueueMenu(false);
                            }}
                            className="flex items-center gap-1 text-xs text-slate-300 hover:text-white bg-white/5 px-2 py-1 rounded transition-colors mt-0.5"
                        >
                            <span>Page {pageIndex + 1} / {numPages}</span>
                            <ChevronDown size={12} className={`transition-transform ${showPageNav ? 'rotate-180' : ''}`} />
                        </button>

                        {showPageNav && (
                            <div className="absolute top-full left-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-64 z-50">
                                <form onSubmit={handleJumpToPage} className="flex flex-col gap-4">
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="text-xs text-slate-400 font-bold uppercase">Go to page</span>
                                        <span className="text-xs text-slate-500">{targetPage} / {numPages}</span>
                                    </div>

                                    <input 
                                        type="range" 
                                        min="1" 
                                        max={numPages} 
                                        value={targetPage}
                                        onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                        className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                    />

                                    <div className="flex gap-2">
                                        <input 
                                            type="number" 
                                            min="1" 
                                            max={numPages}
                                            value={targetPage}
                                            onChange={(e) => setTargetPage(parseInt(e.target.value))}
                                            className="flex-1 bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-center focus:ring-1 focus:ring-blue-500 outline-none"
                                        />
                                        <button 
                                            type="submit"
                                            className="bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded text-sm font-medium"
                                        >
                                            Go
                                        </button>
                                    </div>
                                </form>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>

        <div className="flex items-center gap-2 bg-slate-800/90 backdrop-blur rounded-full px-3 py-1.5 border border-white/10">
             <button 
                onClick={() => setIsDrawingMode(!isDrawingMode)} 
                className={`p-2 rounded-full transition-colors ${isDrawingMode ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                title={isDrawingMode ? "Done Drawing" : "Annotate"}
             >
                <PenTool size={18} />
             </button>

             {isDrawingMode && (
               <>
                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button 
                    onClick={() => setTool('pen')}
                    className={`p-2 rounded-full transition-colors ${tool === 'pen' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <PenTool size={18} />
                  </button>
                  <button 
                    onClick={() => setTool('eraser')}
                    className={`p-2 rounded-full transition-colors ${tool === 'eraser' ? 'text-white bg-white/10' : 'text-slate-400 hover:text-white'}`}
                  >
                     <Eraser size={18} />
                  </button>

                  {tool === 'pen' && (
                    <>
                        <div className="flex items-center gap-1 ml-2">
                            {COLORS.map(c => (
                                <button 
                                key={c}
                                onClick={() => setColor(c)}
                                className={`w-5 h-5 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`}
                                style={{ backgroundColor: c }}
                                />
                            ))}
                        </div>

                        <div className="h-6 w-px bg-white/20 mx-1" />

                        <div className="relative" ref={penSettingsRef}>
                            <button 
                                onClick={() => {
                                    setShowPenSettings(!showPenSettings);
                                    setShowPageNav(false);
                                }}
                                className={`p-2 rounded-full transition-colors ${showPenSettings ? 'bg-white/20 text-white' : 'text-slate-400 hover:text-white'}`}
                                title="Pen Settings"
                            >
                                <Sliders size={18} />
                            </button>
                            {showPenSettings && (
                                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-4 bg-slate-800 border border-slate-700 rounded-xl p-4 shadow-2xl w-56 z-50">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Pen Options</h4>

                                    {/* Preview */}
                                    <div className="bg-slate-900 rounded-lg p-3 mb-4 border border-slate-700/50 flex items-center justify-center overflow-hidden">
                                        <svg width="160" height="40" className="block">
                                            <path 
                                                d="M 20 20 Q 80 5, 140 20" 
                                                stroke={hexToRgba(color, opacity)} 
                                                strokeWidth={lineWidth} 
                                                fill="none" 
                                                strokeLinecap="round"
                                            />
                                        </svg>
                                    </div>

                                    {/* Width Slider */}
                                    <div className="mb-4">
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Width</span>
                                            <span className="text-xs text-slate-300">{lineWidth}px</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="1" 
                                            max="20" 
                                            step="1"
                                            value={lineWidth}
                                            onChange={(e) => setLineWidth(parseInt(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>

                                    {/* Opacity Slider */}
                                    <div>
                                        <div className="flex justify-between mb-1">
                                            <span className="text-xs text-slate-400">Opacity</span>
                                            <span className="text-xs text-slate-300">{Math.round(opacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" 
                                            min="0.1" 
                                            max="1.0" 
                                            step="0.1"
                                            value={opacity}
                                            onChange={(e) => setOpacity(parseFloat(e.target.value))}
                                            className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                                        />
                                    </div>
                                </div>
                            )}
                        </div>
                    </>
                  )}

                  <div className="h-6 w-px bg-white/20 mx-1" />

                  <button onClick={handleUndo} className="p-2 text-slate-400 hover:text-white" title="Undo">
                    <Undo size={18} />
                  </button>

                  <button onClick={handleClear} className="p-2 text-slate-400 hover:text-red-500" title="Clear Page">
                    <Trash2 size={18} />
                  </button>
               </>
             )}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 relative flex items-center justify-center bg-zinc-900 overflow-hidden">
        {(loading || (!workerReady && fileType === 'application/pdf')) ? (
          <div className="animate-spin text-white"><Settings2 size={40} /></div>
        ) : (fileType === 'application/pdf' ? pdfDoc : blobUrl) ? (
            <div 
                ref={containerRef}
                className={`relative w-full h-full flex items-center justify-center select-none ${isDrawingMode ? 'cursor-crosshair' : ''}`}
                style={{ touchAction: 'none' }} // Critical for preventing scroll on mobile while drawing
                onMouseDown={handlePointerDown}
                onMouseMove={handlePointerMove}
                onMouseUp={handlePointerUp}
                onMouseLeave={handlePointerUp}
                onTouchStart={handlePointerDown}
                onTouchMove={handlePointerMove}
                onTouchEnd={handlePointerUp}
            >
                {fileType === 'application/pdf' ? (
                     <canvas 
                        ref={pdfCanvasRef} 
                        className="shadow-2xl pointer-events-none"
                        style={{ maxWidth: '100%', maxHeight: '100%' }}
                     />
                ) : (
                    <img 
                        src={blobUrl || ''} 
                        alt={`Page ${pageIndex + 1}`} 
                        className="max-w-full max-h-full object-contain pointer-events-none select-none shadow-2xl"
                    />
                )}

                {/* SVG Overlay for Annotations */}
                <svg 
                    ref={svgRef}
                    className="absolute inset-0 w-full h-full pointer-events-none" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {visibleStrokes.map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                    {currentStroke && (
                        <path 
                            d={getSvgPath(currentStroke.points)}
                            stroke={currentStroke.color}
                            strokeWidth={currentStroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    )}
                </svg>
            </div>
        ) : (
          <div className="text-white/50">Error loading file</div>
        )}

        {/* Navigation Hit Zones */}
        {!isDrawingMode && !showPageNav && !showPenSettings && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-10 cursor-pointer" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-10 cursor-pointer" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Bottom Control Hint */}
      {!isDrawingMode && !showPageNav && !showPenSettings && !showQueueMenu && (
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-8 z-20 pointer-events-none opacity-0 hover:opacity-100 transition-opacity">
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasPrev && pageIndex === 0) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePagePrev}
             disabled={!hasPrev && pageIndex === 0}
           >
             <ChevronLeft size={32} />
           </button>
           <button 
             className={`p-4 bg-black/50 rounded-full backdrop-blur pointer-events-auto hover:bg-black/80 transition-all ${(!hasNext && pageIndex === numPages - 1) ? 'opacity-30 cursor-not-allowed' : ''}`}
             onClick={handlePageNext}
             disabled={!hasNext && pageIndex === numPages - 1}
           >
             <ChevronRight size={32} />
           </button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        await storage.addSheet(newSheet);
      }
      onRefresh();
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import (Legacy/Standard: Folder = One Sheet)
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      // Sort files by name
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      // Use the parent folder name as the sheet name
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await storage.addSheet(newSheet);
      onRefresh();
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import (Structure Verified)
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            // Check for duplicates
            const duplicates = result.sheets.filter(newSheet => 
                sheets.some(existing => existing.name === newSheet.name)
            );

            let shouldOverwrite = false;
            if (duplicates.length > 0) {
                const message = `${duplicates.length} sheet(s) already exist with the same name (e.g., "${duplicates[0].name}").\n\nDo you want to overwrite them? (Cancel will create duplicates)`;
                shouldOverwrite = window.confirm(message);
            }

            let count = 0;
            for (let sheet of result.sheets) {
                const existing = sheets.find(s => s.name === sheet.name);

                if (existing) {
                    if (shouldOverwrite) {
                        // Overwrite: Use existing ID, preserve tags/icons
                        sheet = {
                            ...sheet,
                            id: existing.id,
                            tags: existing.tags,
                            tagIcons: existing.tagIcons,
                            // dateAdded updates to now, reflecting the modification
                        };
                    }
                }

                await storage.addSheet(sheet);
                count++;
            }
            alert(`Successfully imported ${count} entries.`);
            onRefresh();
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();

    // Find affected setlists
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName); // Add to current sheet

      // Add to global Quick Add list (Optimistic Update)
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };

      const tagExists = allTags.some(t => t.label === tagName);

      if (!tagExists) {
          // Optimistic update
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);

          try {
            await storage.saveTag(newTagDef);
            // Verify sync
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            // Revert
            await loadTags();
          }
      }

      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      // 1. Optimistic Update: Immediately filter out the tag from local state
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);

      try {
        // 2. Perform DB deletion
        await storage.deleteTag(label);

        // 3. Ensure sync (fetch latest from DB to be sure)
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        // On error, reload to restore state
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  // Resolve which icon component to use for a given tag
  const getTagIcon = (tag: string, sheet?: Sheet) => {
    // 1. Check specific sheet overrides (if provided)
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    // 2. Check edit session overrides (for the modal)
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    // 3. Check global presets
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;

    // 4. Fallback
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
        {/* Single Sheet Folder Input */}
        <input 
            type="file"
            ref={folderInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleFolderChange}
        />
        {/* Batch Import Input */}
        <input 
            type="file"
            ref={batchInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleBatchImport}
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';

             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    {isPdf ? (
                        <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                    ) : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDeleteClick(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Sheet?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.sheet?.name}"</span>?
                          This action cannot be undone.
                      </p>
                  </div>

                  {deleteModal.affectedSetlists.length > 0 && (
                      <div className="bg-orange-500/10 border border-orange-500/20 rounded-lg p-3 mb-6">
                          <div className="flex items-center gap-2 text-orange-400 font-bold text-sm mb-1">
                              <AlertTriangle size={14} />
                              <span>Warning</span>
                          </div>
                          <p className="text-orange-300/80 text-xs mb-2">
                              This sheet is currently used in the following setlists and will be removed from them:
                          </p>
                          <ul className="text-xs text-orange-200 list-disc list-inside">
                              {deleteModal.affectedSetlists.map(name => (
                                  <li key={name}>{name}</li>
                              ))}
                          </ul>
                      </div>
                  )}

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={closeEditModal}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist: setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            // Check for duplicates in library
            const duplicates = result.sheets.filter(newSheet => 
                sheets.some(existing => existing.name === newSheet.name)
            );

            let shouldOverwrite = false;
            if (duplicates.length > 0) {
                 const message = `${duplicates.length} sheet(s) in this setlist already exist in your library (e.g., "${duplicates[0].name}").\n\nDo you want to overwrite the existing sheets? (Cancel will create duplicates)`;
                shouldOverwrite = window.confirm(message);
            }

            // Prepare sheets for saving, handling overwrites
            const sheetsToSave = result.sheets.map(sheet => {
                const existing = sheets.find(s => s.name === sheet.name);
                if (existing && shouldOverwrite) {
                    // Reuse existing ID to overwrite
                    return {
                        ...sheet,
                        id: existing.id,
                        tags: existing.tags,
                        tagIcons: existing.tagIcons
                    };
                }
                return sheet;
            });

            // Save all sheets
            for (const sheet of sheetsToSave) {
                await storage.addSheet(sheet);
            }

            // Create Setlist
            // Sort sheets alphabetically for the setlist
            const sortedSheets = [...sheetsToSave].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
            const sortedIds = sortedSheets.map(s => s.id);

            const setlistName = result.setlistName || "Imported Setlist";

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: setlistName,
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);

            alert(`Imported ${sheetsToSave.length} sheets and created setlist "${setlistName}".`);
            onRefresh();
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3 items-start">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2">
                <button 
                    onClick={() => importInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                    title="Import a folder as a setlist (Batch Import + Auto Create Setlist)"
                >
                    <Import size={20} />
                    <span className="hidden sm:inline">Import Setlist</span>
                </button>

                <button 
                    onClick={startCreate}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">New Setlist</span>
                </button>
            </div>

            <input 
                type="file" 
                ref={importInputRef} 
                className="hidden" 
                // @ts-ignore
                webkitdirectory="" 
                directory="" 
                multiple 
                onChange={handleImportSetlist} 
            />
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one or import a folder</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDeleteClick(e, list)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}

      {/* Delete Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Setlist?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.setlist?.name}"</span>?
                          This action cannot be undone. Note: Sheets in the library will NOT be deleted.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, setlist: null })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Unified Import Logic with Duplication Check
  const importSheets = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;

    // Check for duplicates
    const duplicates = newSheets.filter(newSheet => 
        sheets.some(existing => existing.name === newSheet.name)
    );

    let shouldOverwrite = false;
    if (duplicates.length > 0) {
        const message = `${duplicates.length} sheet(s) already exist with the same name (e.g., "${duplicates[0].name}").\n\nClick OK to OVERWRITE existing files.\nClick Cancel to keep both (CREATE DUPLICATES).`;
        shouldOverwrite = window.confirm(message);
    }

    let count = 0;
    for (const sheet of newSheets) {
        const existing = sheets.find(s => s.name === sheet.name);

        let sheetToSave = sheet;

        if (existing) {
            if (shouldOverwrite) {
                // Overwrite: Use existing ID to replace in DB, preserve tags/icons
                // But use the NEW pages/blob content
                sheetToSave = {
                    ...sheet,
                    id: existing.id,
                    tags: existing.tags,
                    tagIcons: existing.tagIcons,
                    dateAdded: Date.now()
                };
            }
        }

        await storage.addSheet(sheetToSave);
        count++;
    }

    if (successMessage) {
        alert(successMessage);
    }
    onRefresh();
  };

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        newSheets.push(newSheet);
      }

      await importSheets(newSheets);
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import (Legacy/Standard: Folder = One Sheet)
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      // Sort files by name
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      // Use the parent folder name as the sheet name
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };

      await importSheets([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import (Structure Verified)
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            await importSheets(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();

    // Find affected setlists
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName); // Add to current sheet

      // Add to global Quick Add list (Optimistic Update)
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };

      const tagExists = allTags.some(t => t.label === tagName);

      if (!tagExists) {
          // Optimistic update
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);

          try {
            await storage.saveTag(newTagDef);
            // Verify sync
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            // Revert
            await loadTags();
          }
      }

      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      // 1. Optimistic Update: Immediately filter out the tag from local state
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);

      try {
        // 2. Perform DB deletion
        await storage.deleteTag(label);

        // 3. Ensure sync (fetch latest from DB to be sure)
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        // On error, reload to restore state
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  // Resolve which icon component to use for a given tag
  const getTagIcon = (tag: string, sheet?: Sheet) => {
    // 1. Check specific sheet overrides (if provided)
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    // 2. Check edit session overrides (for the modal)
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    // 3. Check global presets
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;

    // 4. Fallback
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
        {/* Single Sheet Folder Input */}
        <input 
            type="file"
            ref={folderInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleFolderChange}
        />
        {/* Batch Import Input */}
        <input 
            type="file"
            ref={batchInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleBatchImport}
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';

             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    {isPdf ? (
                        <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                    ) : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDeleteClick(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Sheet?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.sheet?.name}"</span>?
                          This action cannot be undone.
                      </p>
                  </div>

                  {deleteModal.affectedSetlists.length > 0 && (
                      <div className="bg-orange-500/10 border border-orange-500/20 rounded-lg p-3 mb-6">
                          <div className="flex items-center gap-2 text-orange-400 font-bold text-sm mb-1">
                              <AlertTriangle size={14} />
                              <span>Warning</span>
                          </div>
                          <p className="text-orange-300/80 text-xs mb-2">
                              This sheet is currently used in the following setlists and will be removed from them:
                          </p>
                          <ul className="text-xs text-orange-200 list-disc list-inside">
                              {deleteModal.affectedSetlists.map(name => (
                                  <li key={name}>{name}</li>
                              ))}
                          </ul>
                      </div>
                  )}

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={closeEditModal}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist: setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            // Check for duplicates in library
            const duplicates = result.sheets.filter(newSheet => 
                sheets.some(existing => existing.name === newSheet.name)
            );

            let shouldOverwrite = false;
            if (duplicates.length > 0) {
                 const message = `${duplicates.length} sheet(s) in this setlist already exist in your library (e.g., "${duplicates[0].name}").\n\nClick OK to OVERWRITE existing files.\nClick Cancel to keep both (CREATE DUPLICATES).`;
                shouldOverwrite = window.confirm(message);
            }

            // Prepare sheets for saving, handling overwrites
            const sheetsToSave = result.sheets.map(sheet => {
                const existing = sheets.find(s => s.name === sheet.name);
                if (existing && shouldOverwrite) {
                    // Reuse existing ID to overwrite content but keep metadata
                    return {
                        ...sheet,
                        id: existing.id,
                        tags: existing.tags,
                        tagIcons: existing.tagIcons,
                        dateAdded: Date.now()
                    };
                }
                return sheet;
            });

            // Save all sheets
            for (const sheet of sheetsToSave) {
                await storage.addSheet(sheet);
            }

            // Create Setlist
            // Sort sheets alphabetically for the setlist
            const sortedSheets = [...sheetsToSave].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
            const sortedIds = sortedSheets.map(s => s.id);

            const setlistName = result.setlistName || "Imported Setlist";

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: setlistName,
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);

            alert(`Imported ${sheetsToSave.length} sheets and created setlist "${setlistName}".`);
            onRefresh();
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3 items-start">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2">
                <button 
                    onClick={() => importInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                    title="Import a folder as a setlist (Batch Import + Auto Create Setlist)"
                >
                    <Import size={20} />
                    <span className="hidden sm:inline">Import Setlist</span>
                </button>

                <button 
                    onClick={startCreate}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">New Setlist</span>
                </button>
            </div>

            <input 
                type="file" 
                ref={importInputRef} 
                className="hidden" 
                // @ts-ignore
                webkitdirectory="" 
                directory="" 
                multiple 
                onChange={handleImportSetlist} 
            />
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one or import a folder</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDeleteClick(e, list)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}

      {/* Delete Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Setlist?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.setlist?.name}"</span>?
                          This action cannot be undone. Note: Sheets in the library will NOT be deleted.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, setlist: null })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Unified Import Logic with Duplication Check
  const importSheets = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;

    // Fetch latest sheets from DB to ensure we check against current state, bypassing potential prop staleness
    const currentSheets = await storage.getAllSheets();

    // Check for duplicates (Case insensitive trim check)
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );

    let shouldOverwrite = false;
    if (duplicates.length > 0) {
        // List top 3 duplicates for context
        const duplicateNames = duplicates.slice(0, 3).map(s => s.name).join(", ");
        const moreCount = duplicates.length > 3 ? ` and ${duplicates.length - 3} more` : "";

        const message = `${duplicates.length} sheet(s) already exist with the same name (e.g., "${duplicateNames}"${moreCount}).\n\nClick OK to OVERWRITE existing files (updates content, keeps tags).\nClick Cancel to keep both (creates duplicates).`;
        shouldOverwrite = window.confirm(message);
    }

    let count = 0;
    for (const sheet of newSheets) {
        // Find match using the same robust logic
        const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());

        let sheetToSave = sheet;

        if (existing) {
            if (shouldOverwrite) {
                // Overwrite: Use existing ID to replace in DB, preserve tags/icons
                // But use the NEW pages/blob content and new name casing if changed
                sheetToSave = {
                    ...sheet,
                    id: existing.id,
                    tags: existing.tags,
                    tagIcons: existing.tagIcons,
                    dateAdded: Date.now()
                };
            }
        }

        await storage.addSheet(sheetToSave);
        count++;
    }

    if (successMessage) {
        // Small delay to ensure alert doesn't block UI update immediately
        setTimeout(() => alert(successMessage), 100);
    }
    onRefresh();
  };

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        newSheets.push(newSheet);
      }

      await importSheets(newSheets);
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import (Legacy/Standard: Folder = One Sheet)
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      // Sort files by name
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      // Use the parent folder name as the sheet name
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };

      await importSheets([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import (Structure Verified)
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            await importSheets(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();

    // Find affected setlists
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName); // Add to current sheet

      // Add to global Quick Add list (Optimistic Update)
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };

      const tagExists = allTags.some(t => t.label === tagName);

      if (!tagExists) {
          // Optimistic update
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);

          try {
            await storage.saveTag(newTagDef);
            // Verify sync
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            // Revert
            await loadTags();
          }
      }

      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      // 1. Optimistic Update: Immediately filter out the tag from local state
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);

      try {
        // 2. Perform DB deletion
        await storage.deleteTag(label);

        // 3. Ensure sync (fetch latest from DB to be sure)
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        // On error, reload to restore state
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  // Resolve which icon component to use for a given tag
  const getTagIcon = (tag: string, sheet?: Sheet) => {
    // 1. Check specific sheet overrides (if provided)
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    // 2. Check edit session overrides (for the modal)
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    // 3. Check global presets
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;

    // 4. Fallback
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/png, image/jpeg, application/pdf" 
          multiple 
          onChange={handleFileChange} 
        />
        {/* Single Sheet Folder Input */}
        <input 
            type="file"
            ref={folderInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleFolderChange}
        />
        {/* Batch Import Input */}
        <input 
            type="file"
            ref={batchInputRef}
            className="hidden"
            // @ts-ignore
            webkitdirectory="" 
            directory="" 
            multiple
            onChange={handleBatchImport}
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';

             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    {isPdf ? (
                        <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                    ) : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}
                            </span>
                        </div>
                    )}

                    {/* Multi-page indicator */}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}

                    {/* Tag Badges (Icons) */}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>

                {/* Action Buttons */}
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button 
                        onClick={(e) => openEditModal(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur"
                        title="Edit Details"
                    >
                        <PenLine size={14} />
                    </button>
                    <button 
                        onClick={(e) => handleDeleteClick(e, sheet)}
                        className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur"
                        title="Delete"
                    >
                        <Trash2 size={14} />
                    </button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Sheet?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.sheet?.name}"</span>?
                          This action cannot be undone.
                      </p>
                  </div>

                  {deleteModal.affectedSetlists.length > 0 && (
                      <div className="bg-orange-500/10 border border-orange-500/20 rounded-lg p-3 mb-6">
                          <div className="flex items-center gap-2 text-orange-400 font-bold text-sm mb-1">
                              <AlertTriangle size={14} />
                              <span>Warning</span>
                          </div>
                          <p className="text-orange-300/80 text-xs mb-2">
                              This sheet is currently used in the following setlists and will be removed from them:
                          </p>
                          <ul className="text-xs text-orange-200 list-disc list-inside">
                              {deleteModal.affectedSetlists.map(name => (
                                  <li key={name}>{name}</li>
                              ))}
                          </ul>
                      </div>
                  )}

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Modal */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={closeEditModal}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist: setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);

        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            // Check for duplicates in library by fetching fresh state
            const currentSheets = await storage.getAllSheets();

            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            let shouldOverwrite = false;
            if (duplicates.length > 0) {
                 const duplicateNames = duplicates.slice(0, 3).map(s => s.name).join(", ");
                 const moreCount = duplicates.length > 3 ? ` and ${duplicates.length - 3} more` : "";
                 const message = `${duplicates.length} sheet(s) in this setlist already exist in your library (e.g., "${duplicateNames}"${moreCount}).\n\nClick OK to OVERWRITE existing files.\nClick Cancel to keep both (CREATE DUPLICATES).`;
                shouldOverwrite = window.confirm(message);
            }

            // Prepare sheets for saving, handling overwrites
            const sheetsToSave = result.sheets.map(sheet => {
                const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
                if (existing && shouldOverwrite) {
                    // Reuse existing ID to overwrite content but keep metadata
                    return {
                        ...sheet,
                        id: existing.id,
                        tags: existing.tags,
                        tagIcons: existing.tagIcons,
                        dateAdded: Date.now()
                    };
                }
                return sheet;
            });

            // Save all sheets
            for (const sheet of sheetsToSave) {
                await storage.addSheet(sheet);
            }

            // Create Setlist
            // Sort sheets alphabetically for the setlist
            const sortedSheets = [...sheetsToSave].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
            const sortedIds = sortedSheets.map(s => s.id);

            const setlistName = result.setlistName || "Imported Setlist";

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: setlistName,
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);

            alert(`Imported ${sheetsToSave.length} sheets and created setlist "${setlistName}".`);
            onRefresh();
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3 items-start">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2">
                <button 
                    onClick={() => importInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                    title="Import a folder as a setlist (Batch Import + Auto Create Setlist)"
                >
                    <Import size={20} />
                    <span className="hidden sm:inline">Import Setlist</span>
                </button>

                <button 
                    onClick={startCreate}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">New Setlist</span>
                </button>
            </div>

            <input 
                type="file" 
                ref={importInputRef} 
                className="hidden" 
                // @ts-ignore
                webkitdirectory="" 
                directory="" 
                multiple 
                onChange={handleImportSetlist} 
            />
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one or import a folder</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDeleteClick(e, list)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}

      {/* Delete Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Setlist?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.setlist?.name}"</span>?
                          This action cannot be undone. Note: Sheets in the library will NOT be deleted.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, setlist: null })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Step 1: Initiate Import and Check for Duplicates
  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;

    // Fetch latest sheets from DB
    const currentSheets = await storage.getAllSheets();

    // Check for duplicates
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );

    if (duplicates.length > 0) {
        // Trigger Modal
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        // No conflicts, proceed directly
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  // Step 2: Finalize Import (Executed after conflict resolution or if no conflicts)
  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      let count = 0;

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());

          let sheetToSave = sheet;

          if (existing && overwrite) {
              // Overwrite: Use existing ID, preserve tags/icons
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }

          await storage.addSheet(sheetToSave);
          count++;
      }

      setConflictData(null); // Close modal if open

      if (successMessage) {
          // Small timeout to allow modal to close visually first
          setTimeout(() => alert(successMessage), 100);
      }
      onRefresh();
  };

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        newSheets.push(newSheet);
      }

      await initiateImport(newSheets);
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };

      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            alert(result.error);
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      const tagExists = allTags.some(t => t.label === tagName);
      if (!tagExists) {
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);
      try {
        await storage.deleteTag(label);
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';
             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                    {isPdf ? <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" /> : (
                        <div className="flex flex-col items-center gap-2">
                            <Music size={48} className="text-slate-600" />
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">{sheet.pages.length > 1 ? `${sheet.pages.length} Pages` : 'Image'}</span>
                        </div>
                    )}
                    {sheet.pages.length > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {sheet.pages.length}
                        </div>
                    )}
                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>
                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-30">
                    <button onClick={(e) => openEditModal(e, sheet)} className="p-2 bg-black/60 text-white rounded-full hover:bg-blue-600 backdrop-blur" title="Edit Details"><PenLine size={14} /></button>
                    <button onClick={(e) => handleDeleteClick(e, sheet)} className="p-2 bg-black/60 text-white rounded-full hover:bg-red-500 backdrop-blur" title="Delete"><Trash2 size={14} /></button>
                </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Duplicate Conflict Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => {}}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-lg border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-yellow-900/30 rounded-full flex items-center justify-center text-yellow-500 mb-4">
                          <FileWarning size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Duplicates Detected</h3>
                      <p className="text-slate-400 text-sm mb-4">
                          {conflictData.duplicates.length} of the sheets you are importing have the same names as existing sheets in your library.
                      </p>

                      <div className="bg-slate-900/50 rounded-lg p-3 w-full max-h-48 overflow-y-auto mb-4 border border-slate-700 text-left">
                           <ul className="text-sm text-slate-300 space-y-1">
                               {conflictData.duplicates.map((s, i) => (
                                   <li key={i} className="flex items-center gap-2">
                                       <AlertTriangle size={12} className="text-yellow-500" />
                                       <span className="truncate">{s.name}</span>
                                   </li>
                               ))}
                           </ul>
                      </div>

                      <p className="text-slate-500 text-xs">
                          "Overwrite" will update the content of existing sheets but keep their tags and setlist assignments. "Keep Both" will create duplicates.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setConflictData(null)}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={() => finalizeImport(conflictData.newSheets, false, conflictData.successMessage)}
                          className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-medium transition-colors"
                      >
                          <div className="flex items-center justify-center gap-2">
                             <Copy size={16} />
                             <span>Keep Both</span>
                          </div>
                      </button>
                      <button 
                          onClick={() => finalizeImport(conflictData.newSheets, true, conflictData.successMessage)}
                          className="flex-1 py-3 bg-yellow-600 hover:bg-yellow-500 text-white rounded-xl font-medium transition-colors"
                      >
                          <div className="flex items-center justify-center gap-2">
                              <Save size={16} />
                              <span>Overwrite</span>
                          </div>
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Sheet?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.sheet?.name}"</span>?
                          This action cannot be undone.
                      </p>
                  </div>

                  {deleteModal.affectedSetlists.length > 0 && (
                      <div className="bg-orange-500/10 border border-orange-500/20 rounded-lg p-3 mb-6">
                          <div className="flex items-center gap-2 text-orange-400 font-bold text-sm mb-1">
                              <AlertTriangle size={14} />
                              <span>Warning</span>
                          </div>
                          <p className="text-orange-300/80 text-xs mb-2">
                              This sheet is currently used in the following setlists and will be removed from them:
                          </p>
                          <ul className="text-xs text-orange-200 list-disc list-inside">
                              {deleteModal.affectedSetlists.map(name => (
                                  <li key={name}>{name}</li>
                              ))}
                          </ul>
                      </div>
                  )}

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Edit Modal (Existing) */}
      {editingSheet && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={closeEditModal}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-md border border-slate-700 shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                      <h3 className="font-bold text-white">Edit Details</h3>
                      <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20}/></button>
                  </div>
                  <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={editName}
                            onChange={e => setEditName(e.target.value)}
                          />
                      </div>

                      <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Selected Tags</label>
                          <div className="flex flex-wrap gap-2 mb-4 min-h-[32px]">
                              {editTags.map(tag => {
                                  const Icon = getTagIcon(tag);
                                  return (
                                    <span key={tag} className="flex items-center gap-1 bg-blue-600/20 text-blue-300 px-2 py-1 rounded-full text-sm border border-blue-600/30">
                                        <Icon size={12} />
                                        {tag}
                                        <button onClick={() => handleRemoveTag(tag)} className="hover:text-white ml-1"><X size={12}/></button>
                                    </span>
                                  );
                              })}
                              {editTags.length === 0 && <span className="text-slate-500 text-sm italic">No tags selected</span>}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Quick Add</label>
                          <div className="grid grid-cols-3 gap-2 mb-4">
                              {allTags.map(tagDef => {
                                  const isSelected = editTags.includes(tagDef.label);
                                  const Icon = ICON_MAP[tagDef.iconName] || Tag;

                                  return (
                                    <div key={tagDef.label} className="relative group min-h-[58px]">
                                        <button
                                            onClick={() => isSelected ? handleRemoveTag(tagDef.label) : addTag(tagDef.label)}
                                            className={`w-full h-full flex flex-col items-center justify-center p-2 rounded-lg border transition-all ${isSelected ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Icon size={20} className="mb-1" />
                                            <span className="text-[10px] truncate w-full text-center">{tagDef.label}</span>
                                        </button>

                                        {!tagToDelete && (
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setTagToDelete(tagDef.label);
                                                }}
                                                className="absolute -top-1 -right-1 bg-slate-950 text-slate-500 rounded-full p-0.5 border border-slate-700 hover:text-red-500 hover:border-red-500 transition-colors z-10"
                                                title="Delete from Quick Add"
                                            >
                                                <X size={10} />
                                            </button>
                                        )}

                                        {tagToDelete === tagDef.label && (
                                            <div 
                                                className="absolute inset-0 bg-slate-950/90 border border-red-500 rounded-lg flex items-center justify-around z-20 animate-in fade-in zoom-in duration-150 backdrop-blur-sm"
                                                onClick={e => e.stopPropagation()}
                                            >
                                                <button 
                                                    onClick={() => setTagToDelete(null)}
                                                    className="p-1 rounded-full bg-slate-800 text-slate-400 hover:text-white transition-colors"
                                                >
                                                    <X size={16} />
                                                </button>
                                                <span className="text-[10px] font-bold text-red-500 uppercase tracking-wider">Del?</span>
                                                <button 
                                                    onClick={() => confirmDeleteTag(tagDef.label)}
                                                    className="p-1 rounded-full bg-red-600 text-white hover:bg-red-500 transition-colors shadow-lg shadow-red-900/50"
                                                >
                                                    <Check size={16} />
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                  )
                              })}
                          </div>

                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Create Custom Tag</label>
                          <div className="flex gap-2 items-center">
                            {/* Icon Picker Trigger */}
                            <div className="relative">
                                <button 
                                    onClick={() => setShowIconPicker(!showIconPicker)}
                                    className="w-10 h-10 flex items-center justify-center bg-slate-900 border border-slate-700 rounded-lg hover:border-blue-500 transition-colors text-slate-300"
                                    title="Choose icon"
                                >
                                    <CurrentInputIcon size={18} />
                                </button>

                                {showIconPicker && (
                                    <div className="absolute bottom-full left-0 mb-2 p-3 bg-slate-800 border border-slate-600 rounded-xl shadow-2xl z-50 w-64">
                                        <div className="grid grid-cols-6 gap-2">
                                            {Object.keys(ICON_MAP).map(iconName => {
                                                const Icon = ICON_MAP[iconName];
                                                const isSelected = selectedIconName === iconName;
                                                return (
                                                    <button 
                                                        key={iconName}
                                                        onClick={() => {
                                                            setSelectedIconName(iconName);
                                                            setShowIconPicker(false);
                                                        }}
                                                        className={`p-2 rounded hover:bg-slate-700 flex items-center justify-center ${isSelected ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
                                                    >
                                                        <Icon size={16} />
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>

                            <input 
                                type="text" 
                                placeholder="Tag name..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none text-sm h-10"
                                value={tagInput}
                                onChange={e => setTagInput(e.target.value)}
                            />

                            <button 
                                onClick={handleAddTag}
                                disabled={!tagInput.trim()}
                                className="h-10 px-4 bg-slate-700 hover:bg-blue-600 text-white rounded-lg flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                title="Add Tag"
                            >
                                <Plus size={18} />
                            </button>
                          </div>
                      </div>
                  </div>
                  <div className="p-4 border-t border-slate-700 flex justify-end gap-3 bg-slate-900/50">
                      <button onClick={closeEditModal} className="px-4 py-2 text-slate-300 hover:text-white">Cancel</button>
                      <button onClick={saveEdits} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500">
                          <Save size={16} /> Save
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import, FileWarning, AlertTriangle, Copy, Save } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    setlistName?: string;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  // Toggle selection: append to end if adding, remove if existing
  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, index: number) => {
    setDraggedIndex(index);
    // Required for Firefox
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', index.toString());
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetIndex: number) => {
    e.preventDefault();
    if (draggedIndex === null || draggedIndex === targetIndex) return;

    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(draggedIndex, 1);
    newIds.splice(targetIndex, 0, removed);

    setSelectedSheetIds(newIds);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist: setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  // Step 1: Initiate Import
  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            alert(result.error);
            return;
        }

        if (result.sheets.length > 0) {
            // Check for duplicates in library by fetching fresh state
            const currentSheets = await storage.getAllSheets();

            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            if (duplicates.length > 0) {
                setConflictData({ newSheets: result.sheets, duplicates, setlistName: result.setlistName });
            } else {
                await finalizeSetlistImport(result.sheets, false, result.setlistName);
            }
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Step 2: Finalize Import
  const finalizeSetlistImport = async (newSheets: Sheet[], overwrite: boolean, setlistName?: string) => {
        const currentSheets = await storage.getAllSheets();

        // Prepare sheets for saving, handling overwrites
        const sheetsToSave = newSheets.map(sheet => {
            const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
            if (existing && overwrite) {
                // Reuse existing ID to overwrite content but keep metadata
                return {
                    ...sheet,
                    id: existing.id,
                    tags: existing.tags,
                    tagIcons: existing.tagIcons,
                    dateAdded: Date.now()
                };
            }
            return sheet;
        });

        // Save all sheets
        for (const sheet of sheetsToSave) {
            await storage.addSheet(sheet);
        }

        // Create Setlist
        // Sort sheets alphabetically for the setlist
        const sortedSheets = [...sheetsToSave].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
        const sortedIds = sortedSheets.map(s => s.id);

        const name = setlistName || "Imported Setlist";

        const newSetlist: Setlist = {
            id: crypto.randomUUID(),
            name: name,
            sheetIds: sortedIds,
            dateCreated: Date.now()
        };

        await storage.saveSetlist(newSetlist);

        setConflictData(null);
        setTimeout(() => alert(`Imported ${sheetsToSave.length} sheets and created setlist "${name}".`), 100);
        onRefresh();
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            {/* Library Selection */}
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>

                {/* Library Filter */}
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>

                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                    {sheet.tags && sheet.tags.length > 0 && (
                                        <div className="flex gap-1 mt-1">
                                            {sheet.tags.slice(0,2).map(t => <span key={t} className="text-[10px] bg-slate-700 px-1 rounded text-slate-400">{t}</span>)}
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {filteredLibrary.length === 0 && (
                        <div className="text-center text-slate-500 text-sm py-4">No matching sheets</div>
                    )}
                </div>
            </div>

            {/* Selected Order with DnD */}
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragging = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    draggable="true"
                                    onDragStart={(e) => handleDragStart(e, index)}
                                    onDragOver={(e) => handleDragOver(e, index)}
                                    onDrop={(e) => handleDrop(e, index)}
                                    onDragEnd={() => setDraggedIndex(null)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragging ? 'opacity-50 border-blue-500 bg-slate-700' : 'border-slate-700'}`}
                                >
                                    <div className="p-2 text-slate-500 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2">{sheet.name}</span>

                                    <button 
                                        onClick={() => toggleSelection(id)}
                                        className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                        title="Remove"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3 items-start">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2">
                <button 
                    onClick={() => importInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                    title="Import a folder as a setlist (Batch Import + Auto Create Setlist)"
                >
                    <Import size={20} />
                    <span className="hidden sm:inline">Import Setlist</span>
                </button>

                <button 
                    onClick={startCreate}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">New Setlist</span>
                </button>
            </div>

            <input 
                type="file" 
                ref={importInputRef} 
                className="hidden" 
                // @ts-ignore
                webkitdirectory="" 
                directory="" 
                multiple 
                onChange={handleImportSetlist} 
            />
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
          <p className="text-slate-500 text-sm mt-1">Create one or import a folder</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button 
                      onClick={() => startEdit(list)}
                      className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Edit Setlist"
                    >
                       <Pencil size={18} />
                   </button>
                   <button 
                      onClick={(e) => handleDeleteClick(e, list)}
                      className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg hover:bg-slate-900"
                      title="Delete Setlist"
                    >
                       <Trash2 size={18} />
                   </button>
               </div>
            </div>
          ))}
        </div>
      )}

      {/* Duplicate Conflict Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => {}}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-lg border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-yellow-900/30 rounded-full flex items-center justify-center text-yellow-500 mb-4">
                          <FileWarning size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Duplicates Detected</h3>
                      <p className="text-slate-400 text-sm mb-4">
                          {conflictData.duplicates.length} of the sheets in this setlist match existing sheets in your library.
                      </p>

                      <div className="bg-slate-900/50 rounded-lg p-3 w-full max-h-48 overflow-y-auto mb-4 border border-slate-700 text-left">
                           <ul className="text-sm text-slate-300 space-y-1">
                               {conflictData.duplicates.map((s, i) => (
                                   <li key={i} className="flex items-center gap-2">
                                       <AlertTriangle size={12} className="text-yellow-500" />
                                       <span className="truncate">{s.name}</span>
                                   </li>
                               ))}
                           </ul>
                      </div>

                      <p className="text-slate-500 text-xs">
                          "Overwrite" will update existing sheets but keep metadata. "Keep Both" will create duplicates. Both options will include these sheets in the new setlist.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setConflictData(null)}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={() => finalizeSetlistImport(conflictData.newSheets, false, conflictData.setlistName)}
                          className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-medium transition-colors"
                      >
                          <div className="flex items-center justify-center gap-2">
                             <Copy size={16} />
                             <span>Keep Both</span>
                          </div>
                      </button>
                      <button 
                          onClick={() => finalizeSetlistImport(conflictData.newSheets, true, conflictData.setlistName)}
                          className="flex-1 py-3 bg-yellow-600 hover:bg-yellow-500 text-white rounded-xl font-medium transition-colors"
                      >
                          <div className="flex items-center justify-center gap-2">
                              <Save size={16} />
                              <span>Overwrite</span>
                          </div>
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Modal */}
      {deleteModal.isOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
              <div className="bg-slate-800 rounded-2xl w-full max-w-sm border border-slate-700 shadow-2xl p-6" onClick={e => e.stopPropagation()}>
                  <div className="flex flex-col items-center text-center mb-6">
                      <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center text-red-500 mb-4">
                          <Trash2 size={32} />
                      </div>
                      <h3 className="text-xl font-bold text-white mb-2">Delete Setlist?</h3>
                      <p className="text-slate-400 text-sm">
                          Are you sure you want to delete <span className="font-bold text-white">"{deleteModal.setlist?.name}"</span>?
                          This action cannot be undone. Note: Sheets in the library will NOT be deleted.
                      </p>
                  </div>

                  <div className="flex gap-3">
                      <button 
                          onClick={() => setDeleteModal({ isOpen: false, setlist: null })}
                          className="flex-1 py-3 bg-slate-700 hover:bg-slate-600 text-white rounded-xl font-medium transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                          onClick={confirmDelete}
                          className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-medium transition-colors shadow-lg shadow-red-900/20"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useState, useEffect, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { AppView, Sheet, Setlist, ViewerState } from './types';
import { storage } from './services/storage';
import { Music, ListMusic, Settings, HelpCircle, X, FileText, FolderUp, PenTool, Zap, Keyboard, MousePointerClick, Library as LibraryIcon, Layers } from 'lucide-react';
import Library from './components/Library';
import Setlists from './components/Setlists';
import Viewer from './components/Viewer';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.LIBRARY);
  // Track previous view to return to after closing viewer
  const [previousView, setPreviousView] = useState<AppView>(AppView.LIBRARY);

  const [sheets, setSheets] = useState<Sheet[]>([]);
  const [setlists, setSetlists] = useState<Setlist[]>([]);
  const [viewerState, setViewerState] = useState<ViewerState | null>(null);
  const [showHelp, setShowHelp] = useState(false);

  const loadData = useCallback(async () => {
    try {
      await storage.init();
      const loadedSheets = await storage.getAllSheets();
      const loadedSetlists = await storage.getAllSetlists();
      setSheets(loadedSheets.sort((a, b) => b.dateAdded - a.dateAdded));
      setSetlists(loadedSetlists.sort((a, b) => b.dateCreated - a.dateCreated));
    } catch (error) {
      console.error("Failed to load data", error);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Navigation Logic
  const openViewer = (sheetId: string) => {
    setPreviousView(AppView.LIBRARY);
    setViewerState({
      activeSetlistId: null,
      queue: [sheetId],
      currentIndex: 0
    });
    setView(AppView.VIEWER);
  };

  const playSetlist = (setlist: Setlist) => {
    if (setlist.sheetIds.length === 0) return;
    setPreviousView(AppView.SETLISTS);
    setViewerState({
      activeSetlistId: setlist.id,
      queue: setlist.sheetIds,
      currentIndex: 0
    });
    setView(AppView.VIEWER);
  };

  const handleNext = () => {
    if (!viewerState) return;
    if (viewerState.currentIndex < viewerState.queue.length - 1) {
      setViewerState({ ...viewerState, currentIndex: viewerState.currentIndex + 1 });
    }
  };

  const handlePrev = () => {
    if (!viewerState) return;
    if (viewerState.currentIndex > 0) {
      setViewerState({ ...viewerState, currentIndex: viewerState.currentIndex - 1 });
    }
  };

  const handleJumpTo = (index: number) => {
    if (!viewerState) return;
    if (index >= 0 && index < viewerState.queue.length) {
        setViewerState({ ...viewerState, currentIndex: index });
    }
  };

  const closeViewer = () => {
    setViewerState(null);
    setView(previousView);
  };

  // Get current sheet title for viewer
  const getCurrentSheetTitle = () => {
    if (!viewerState) return '';
    const currentId = viewerState.queue[viewerState.currentIndex];
    const sheet = sheets.find(s => s.id === currentId);
    return sheet ? sheet.name : 'Unknown';
  };

  if (view === AppView.VIEWER && viewerState) {
    const currentSheetId = viewerState.queue[viewerState.currentIndex];

    // Prepare queue data for the Viewer's dropdown
    const queueData = viewerState.queue.map(id => {
        const s = sheets.find(sheet => sheet.id === id);
        return { id, name: s ? s.name : 'Unknown Sheet' };
    });

    return (
      <Viewer 
        sheetId={currentSheetId}
        title={getCurrentSheetTitle()}
        onClose={closeViewer}
        onNext={handleNext}
        onPrev={handlePrev}
        hasNext={viewerState.currentIndex < viewerState.queue.length - 1}
        hasPrev={viewerState.currentIndex > 0}
        queue={queueData}
        currentQueueIndex={viewerState.currentIndex}
        onJumpTo={handleJumpTo}
      />
    );
  }

  return (
    <div className="flex h-screen bg-slate-900 text-slate-100 font-sans">
      {/* Sidebar Navigation */}
      <nav className="w-20 md:w-64 bg-slate-950 border-r border-slate-800 flex flex-col justify-between z-10">
        <div>
          <div className="p-6 flex items-center gap-3">
             <div className="w-8 h-8 bg-gradient-to-tr from-blue-600 to-purple-500 rounded-lg flex items-center justify-center shrink-0">
               <Music size={18} className="text-white" />
             </div>
             <span className="font-bold text-xl hidden md:block tracking-tight">OpusView</span>
          </div>

          <div className="mt-6 px-3 space-y-2">
            <button 
              onClick={() => setView(AppView.LIBRARY)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${view === AppView.LIBRARY ? 'bg-blue-600/10 text-blue-400' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-900'}`}
            >
              <LibraryIcon size={22} />
              <span className="font-medium hidden md:block">Library</span>
            </button>
            <button 
              onClick={() => setView(AppView.SETLISTS)}
              className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${view === AppView.SETLISTS ? 'bg-blue-600/10 text-blue-400' : 'text-slate-400 hover:text-slate-200 hover:bg-slate-900'}`}
            >
              <ListMusic size={22} />
              <span className="font-medium hidden md:block">Setlists</span>
            </button>
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 flex flex-col gap-4">
           <button 
             onClick={() => setShowHelp(true)} 
             className="flex items-center gap-4 text-slate-400 hover:text-white transition-colors group w-full"
             title="App Instructions"
           >
             <HelpCircle size={22} className="group-hover:text-blue-400 transition-colors" />
             <span className="text-sm font-medium hidden md:block group-hover:text-blue-100">Help & Guide</span>
           </button>

          <div className="flex items-center gap-4 text-slate-600">
